1	package com.reslife.api.security;
2	
3	import com.reslife.api.domain.user.UserRepository;
4	import org.springframework.security.core.userdetails.UserDetails;
5	import org.springframework.security.core.userdetails.UserDetailsService;
6	import org.springframework.security.core.userdetails.UsernameNotFoundException;
7	import org.springframework.stereotype.Service;
8	import org.springframework.transaction.annotation.Transactional;
9	
10	/**
11	 * Loads a {@link ReslifeUserDetails} from the database.
12	 *
13	 * <p>Used by Spring Security to re-validate the session principal on each request.
14	 * The @SQLRestriction("deleted_at IS NULL") on {@link com.reslife.api.domain.user.User}
15	 * ensures that soft-deleted accounts cannot authenticate — returning empty here causes
16	 * Spring Security to treat the session as invalid.
17	 *
18	 * <p>The error message intentionally does not mention whether the username exists,
19	 * to prevent username-enumeration via error messages.
20	 */
21	@Service
22	@Transactional(readOnly = true)
23	public class UserDetailsServiceImpl implements UserDetailsService {
24	
25	    private final UserRepository userRepository;
26	
27	    public UserDetailsServiceImpl(UserRepository userRepository) {
28	        this.userRepository = userRepository;
29	    }
30	
31	    @Override
32	    public UserDetails loadUserByUsername(String username) throws UsernameNotFoundException {
33	        return userRepository.findByUsernameIgnoreCase(username)
34	                .or(() -> userRepository.findByEmailIgnoreCase(username))
35	                .map(ReslifeUserDetails::from)
36	                .orElseThrow(() -> new UsernameNotFoundException("Bad credentials"));
37	    }
38	}
