1	package com.reslife.api.domain.resident;
2	
3	import com.reslife.api.domain.housing.CheckInStatus;
4	import com.reslife.api.domain.housing.BookingPolicyCheckRequest;
5	import com.reslife.api.domain.housing.BookingPolicyCheckResponse;
6	import com.reslife.api.domain.housing.BookingPolicyEnforcementService;
7	import com.reslife.api.domain.housing.MoveInRecordRequest;
8	import com.reslife.api.domain.housing.MoveInRecordResponse;
9	import com.reslife.api.encryption.SensitiveAccessLevel;
10	import com.reslife.api.security.ReslifeUserDetails;
11	import jakarta.validation.Valid;
12	import org.springframework.data.domain.Page;
13	import org.springframework.data.domain.Pageable;
14	import org.springframework.http.HttpStatus;
15	import org.springframework.http.ResponseEntity;
16	import org.springframework.security.access.prepost.PreAuthorize;
17	import org.springframework.security.core.annotation.AuthenticationPrincipal;
18	import org.springframework.web.bind.annotation.*;
19	
20	import java.util.List;
21	import java.util.UUID;
22	
23	/**
24	 * REST endpoints for resident records.
25	 *
26	 * <h3>Access control</h3>
27	 * <ul>
28	 *   <li>All authenticated users can list and fetch residents, but
29	 *       sensitive fields (date of birth, emergency contact details)
30	 *       are {@code null} unless the caller holds a staff or admin role.</li>
31	 *   <li>Create, update, and emergency-contact management require staff/admin.</li>
32	 *   <li>Emergency-contact reads require staff/admin.</li>
33	 * </ul>
34	 */
35	@RestController
36	@RequestMapping("/api/residents")
37	public class ResidentController {
38	
39	    private static final String STAFF_ROLES =
40	            "hasAnyRole('ADMIN','HOUSING_ADMINISTRATOR','DIRECTOR'," +
41	            "'RESIDENT_DIRECTOR','RESIDENT_ASSISTANT','RESIDENCE_STAFF','STAFF')";
42	
43	    private final ResidentService residentService;
44	    private final BookingPolicyEnforcementService bookingPolicyEnforcementService;
45	
46	    public ResidentController(ResidentService residentService,
47	                              BookingPolicyEnforcementService bookingPolicyEnforcementService) {
48	        this.residentService = residentService;
49	        this.bookingPolicyEnforcementService = bookingPolicyEnforcementService;
50	    }
51	
52	    // ── Directory ─────────────────────────────────────────────────────────────
53	
54	    @GetMapping
55	    public Page<ResidentResponse> list(
56	            @RequestParam(required = false) String q,
57	            @RequestParam(required = false) String building,
58	            @RequestParam(required = false) Integer classYear,
59	            @RequestParam(required = false) CheckInStatus moveInStatus,
60	            Pageable pageable,
61	            @AuthenticationPrincipal ReslifeUserDetails principal) {
62	        SensitiveAccessLevel level = SensitiveAccessLevel.from(principal.getAuthorities());
63	        return residentService.search(q, building, classYear, moveInStatus, pageable)
64	                .map(r -> ResidentResponse.from(r, level));
65	    }
66	
67	    @GetMapping("/filter-options")
68	    public FilterOptionsResponse filterOptions() {
69	        return residentService.filterOptions();
70	    }
71	
72	    // ── Duplicate check ───────────────────────────────────────────────────────
73	
74	    /**
75	     * Pre-create duplicate check.
76	     * Returns the list of likely duplicate residents — empty list means no duplicates found.
77	     *
78	     * @param excludeId  pass the current resident's ID when editing, so the record
79	     *                   is not reported as its own duplicate
80	     */
81	    @GetMapping("/duplicate-check")
82	    @PreAuthorize(STAFF_ROLES)
83	    public DuplicateCheckResponse duplicateCheck(
84	            @RequestParam(required = false) String firstName,
85	            @RequestParam(required = false) String lastName,
86	            @RequestParam(required = false) String email,
87	            @RequestParam(required = false) String studentId,
88	            @RequestParam(required = false) UUID excludeId) {
89	        return residentService.checkDuplicates(firstName, lastName, email, studentId, excludeId);
90	    }
91	
92	    // ── Single resident ───────────────────────────────────────────────────────
93	
94	    @GetMapping("/{id}")
95	    public ResidentResponse get(
96	            @PathVariable UUID id,
97	            @AuthenticationPrincipal ReslifeUserDetails principal) {
98	        SensitiveAccessLevel level = SensitiveAccessLevel.from(principal.getAuthorities());
99	        return ResidentResponse.from(residentService.findById(id), level);
100	    }
101	
102	    // ── Create ────────────────────────────────────────────────────────────────
103	
104	    /**
105	     * Creates a resident.
106	     *
107	     * <p>Without {@code ?force=true}: returns {@code 409 Conflict} with a
108	     * {@link DuplicateCheckResponse} body if likely duplicates are found —
109	     * the client should present the candidates and let the user confirm before
110	     * retrying with {@code force=true}.
111	     *
112	     * <p>With {@code ?force=true}: skips duplicate detection and creates regardless.
113	     */
114	    @PostMapping
115	    @PreAuthorize(STAFF_ROLES)
116	    public ResponseEntity<ResidentResponse> create(
117	            @Valid @RequestBody ResidentRequest req,
118	            @RequestParam(defaultValue = "false") boolean force,
119	            @AuthenticationPrincipal ReslifeUserDetails principal) {
120	        SensitiveAccessLevel level = SensitiveAccessLevel.from(principal.getAuthorities());
121	        ResidentResponse response = ResidentResponse.from(
122	                residentService.create(req, force), level);
123	        return ResponseEntity.status(HttpStatus.CREATED).body(response);
124	    }
125	
126	    // ── Update ────────────────────────────────────────────────────────────────
127	
128	    @PutMapping("/{id}")
129	    @PreAuthorize(STAFF_ROLES)
130	    public ResidentResponse update(
131	            @PathVariable UUID id,
132	            @Valid @RequestBody ResidentRequest req,
133	            @AuthenticationPrincipal ReslifeUserDetails principal) {
134	        SensitiveAccessLevel level = SensitiveAccessLevel.from(principal.getAuthorities());
135	        return ResidentResponse.from(residentService.update(id, req), level);
136	    }
137	
138	    // ── Soft delete ───────────────────────────────────────────────────────────
139	
140	    @DeleteMapping("/{id}")
141	    @PreAuthorize("hasAnyRole('ADMIN','HOUSING_ADMINISTRATOR','DIRECTOR')")
142	    @ResponseStatus(HttpStatus.NO_CONTENT)
143	    public void delete(@PathVariable UUID id) {
144	        residentService.softDelete(id);
145	    }
146	
147	    // ── Emergency contacts ────────────────────────────────────────────────────
148	
149	    @GetMapping("/{id}/emergency-contacts")
150	    @PreAuthorize(STAFF_ROLES)
151	    public List<EmergencyContactResponse> getEmergencyContacts(
152	            @PathVariable UUID id,
153	            @AuthenticationPrincipal ReslifeUserDetails principal) {
154	        SensitiveAccessLevel level = SensitiveAccessLevel.from(principal.getAuthorities());
155	        return residentService.findEmergencyContacts(id)
156	                .stream()
157	                .map(c -> EmergencyContactResponse.from(c, level))
158	                .toList();
159	    }
160	
161	    @PostMapping("/{id}/emergency-contacts")
162	    @PreAuthorize(STAFF_ROLES)
163	    @ResponseStatus(HttpStatus.CREATED)
164	    public EmergencyContactResponse addEmergencyContact(
165	            @PathVariable UUID id,
166	            @Valid @RequestBody EmergencyContactRequest req,
167	            @AuthenticationPrincipal ReslifeUserDetails principal) {
168	        SensitiveAccessLevel level = SensitiveAccessLevel.from(principal.getAuthorities());
169	        return EmergencyContactResponse.from(
170	                residentService.addEmergencyContact(id, req), level);
171	    }
172	
173	    @PutMapping("/{id}/emergency-contacts/{contactId}")
174	    @PreAuthorize(STAFF_ROLES)
175	    public EmergencyContactResponse updateEmergencyContact(
176	            @PathVariable UUID id,
177	            @PathVariable UUID contactId,
178	            @Valid @RequestBody EmergencyContactRequest req,
179	            @AuthenticationPrincipal ReslifeUserDetails principal) {
180	        SensitiveAccessLevel level = SensitiveAccessLevel.from(principal.getAuthorities());
181	        return EmergencyContactResponse.from(
182	                residentService.updateEmergencyContact(id, contactId, req), level);
183	    }
184	
185	    @DeleteMapping("/{id}/emergency-contacts/{contactId}")
186	    @PreAuthorize(STAFF_ROLES)
187	    @ResponseStatus(HttpStatus.NO_CONTENT)
188	    public void removeEmergencyContact(
189	            @PathVariable UUID id,
190	            @PathVariable UUID contactId) {
191	        residentService.removeEmergencyContact(id, contactId);
192	    }
193	
194	    // ── Move-in records ───────────────────────────────────────────────────────
195	
196	    @GetMapping("/{id}/move-in-records")
197	    @PreAuthorize(STAFF_ROLES)
198	    public List<MoveInRecordResponse> getMoveInRecords(@PathVariable UUID id) {
199	        return residentService.findMoveInRecords(id)
200	                .stream()
201	                .map(MoveInRecordResponse::from)
202	                .toList();
203	    }
204	
205	    @PostMapping("/{id}/move-in-records")
206	    @PreAuthorize(STAFF_ROLES)
207	    @ResponseStatus(HttpStatus.CREATED)
208	    public MoveInRecordResponse addMoveInRecord(
209	            @PathVariable UUID id,
210	            @Valid @RequestBody MoveInRecordRequest req) {
211	        return MoveInRecordResponse.from(residentService.addMoveInRecord(id, req));
212	    }
213	
214	    @PutMapping("/{id}/move-in-records/{recordId}")
215	    @PreAuthorize(STAFF_ROLES)
216	    public MoveInRecordResponse updateMoveInRecord(
217	            @PathVariable UUID id,
218	            @PathVariable UUID recordId,
219	            @Valid @RequestBody MoveInRecordRequest req) {
220	        return MoveInRecordResponse.from(residentService.updateMoveInRecord(id, recordId, req));
221	    }
222	
223	    // ── Booking policy enforcement preview ─────────────────────────────────────
224	
225	    /**
226	     * Evaluates a proposed booking date/building against the currently active
227	     * booking policy and the resident's recent no-show history.
228	     */
229	    @PostMapping("/{id}/booking-policy-check")
230	    @PreAuthorize(STAFF_ROLES)
231	    public BookingPolicyCheckResponse checkBookingPolicy(
232	            @PathVariable UUID id,
233	            @Valid @RequestBody BookingPolicyCheckRequest req) {
234	        return bookingPolicyEnforcementService.evaluate(id, req);
235	    }
236	}
