1	package com.reslife.api.domain.resident;
2	
3	import jakarta.servlet.http.HttpServletResponse;
4	import jakarta.validation.Valid;
5	import org.springframework.http.HttpStatus;
6	import org.springframework.http.MediaType;
7	import org.springframework.security.access.prepost.PreAuthorize;
8	import org.springframework.web.bind.annotation.*;
9	import org.springframework.web.multipart.MultipartFile;
10	
11	import java.io.IOException;
12	import java.io.OutputStreamWriter;
13	import java.io.Writer;
14	import java.nio.charset.StandardCharsets;
15	import java.time.LocalDate;
16	
17	/**
18	 * REST endpoints for bulk CSV import and export of resident data.
19	 *
20	 * <pre>
21	 * POST /api/residents/import/preview   multipart — parse + validate, no DB writes
22	 * POST /api/residents/import/commit    JSON       — apply operator decisions
23	 * GET  /api/residents/export.csv                 — download all residents as CSV
24	 * </pre>
25	 *
26	 * <p>All endpoints require staff or admin role.
27	 */
28	@RestController
29	@RequestMapping("/api/residents")
30	public class ResidentImportExportController {
31	
32	    private static final String STAFF_ROLES =
33	            "hasAnyRole('ADMIN','HOUSING_ADMINISTRATOR','DIRECTOR'," +
34	            "'RESIDENT_DIRECTOR','RESIDENT_ASSISTANT','RESIDENCE_STAFF','STAFF')";
35	
36	    private final ResidentImportExportService importExportService;
37	
38	    public ResidentImportExportController(ResidentImportExportService importExportService) {
39	        this.importExportService = importExportService;
40	    }
41	
42	    // ── Import: preview ───────────────────────────────────────────────────────
43	
44	    /**
45	     * Parses a CSV upload and returns per-row validation and duplicate results.
46	     *
47	     * <p>No records are created or modified. The response is used to populate
48	     * the preview table in the UI.
49	     *
50	     * @param file  a UTF-8 CSV with the header row:
51	     *              {@code studentId, firstName, lastName, email, phone, dateOfBirth,
52	     *              enrollmentStatus, department, classYear, roomNumber, buildingName}
53	     */
54	    @PostMapping(value = "/import/preview",
55	                 consumes = MediaType.MULTIPART_FORM_DATA_VALUE)
56	    @PreAuthorize(STAFF_ROLES)
57	    public ImportPreviewResponse preview(
58	            @RequestPart("file") MultipartFile file) throws IOException {
59	        if (file.isEmpty()) {
60	            throw new IllegalArgumentException("Uploaded file is empty.");
61	        }
62	        String contentType = file.getContentType();
63	        // Accept text/csv, text/plain, application/vnd.ms-excel (Excel CSV export), or blank
64	        if (contentType != null && !contentType.isBlank()
65	                && !contentType.startsWith("text/")
66	                && !contentType.equals("application/vnd.ms-excel")
67	                && !contentType.equals("application/octet-stream")) {
68	            throw new IllegalArgumentException(
69	                    "Expected a CSV file (text/csv), got: " + contentType);
70	        }
71	        return importExportService.preview(file);
72	    }
73	
74	    // ── Import: commit ────────────────────────────────────────────────────────
75	
76	    /**
77	     * Commits the operator's per-row decisions.
78	     *
79	     * <p>Each row is processed independently; failures are returned in the
80	     * response rather than aborting the whole batch.
81	     */
82	    @PostMapping("/import/commit")
83	    @PreAuthorize(STAFF_ROLES)
84	    @ResponseStatus(HttpStatus.OK)
85	    public ImportCommitResponse commit(
86	            @Valid @RequestBody ImportCommitRequest req) {
87	        return importExportService.commit(req);
88	    }
89	
90	    // ── Export ────────────────────────────────────────────────────────────────
91	
92	    /**
93	     * Streams all active residents as a UTF-8 CSV attachment.
94	     *
95	     * <p>Date-of-birth is included in plain text (decrypted by JPA).
96	     * The endpoint is restricted to staff/admin roles, so sensitivity
97	     * concerns are handled at the access-control layer.
98	     */
99	    @GetMapping("/export.csv")
100	    @PreAuthorize(STAFF_ROLES)
101	    public void exportCsv(HttpServletResponse response) throws IOException {
102	        String filename = "residents-" + LocalDate.now() + ".csv";
103	        response.setContentType("text/csv; charset=UTF-8");
104	        response.setHeader("Content-Disposition",
105	                "attachment; filename=\"" + filename + "\"");
106	        // UTF-8 BOM so Excel opens the file correctly without re-encoding
107	        response.getOutputStream().write(0xEF);
108	        response.getOutputStream().write(0xBB);
109	        response.getOutputStream().write(0xBF);
110	
111	        try (Writer writer = new OutputStreamWriter(
112	                response.getOutputStream(), StandardCharsets.UTF_8)) {
