1	import React, { createContext, useCallback, useContext, useEffect, useState } from 'react';
2	import { api } from '../api/client';
3	
4	const AuthContext = createContext(null);
5	
6	/**
7	 * Provides the current authenticated user and auth actions (login / logout)
8	 * to the entire component tree.
9	 *
10	 * On mount it calls GET /api/auth/csrf (forces the XSRF-TOKEN cookie to be
11	 * set) then GET /api/auth/me (restores an existing session if present).
12	 */
13	export function AuthProvider({ children }) {
14	  const [user, setUser]       = useState(null);   // LoginResponse | null
15	  const [loading, setLoading] = useState(true);
16	  const [error, setError]     = useState(null);
17	
18	  // -----------------------------------------------------------------------
19	  // Bootstrap: restore session on page load
20	  // -----------------------------------------------------------------------
21	  useEffect(() => {
22	    (async () => {
23	      try {
24	        // Prime the CSRF cookie before any mutating request
25	        await api.get('/api/auth/csrf');
26	        // Restore existing session (returns 401 if none — caught below)
27	        const me = await api.get('/api/auth/me');
28	        setUser(me);
29	      } catch {
30	        // Not logged in — this is the normal unauthenticated state
31	        setUser(null);
32	      } finally {
33	        setLoading(false);
34	      }
35	    })();
36	  }, []);
37	
38	  // -----------------------------------------------------------------------
39	  // Login
40	  // -----------------------------------------------------------------------
41	  const login = useCallback(async (identifier, password) => {
42	    setError(null);
43	    const me = await api.post('/api/auth/login', { identifier, password });
44	    setUser(me);
45	    return me;
46	  }, []);
47	
48	  // -----------------------------------------------------------------------
49	  // Logout
50	  // -----------------------------------------------------------------------
51	  const logout = useCallback(async () => {
52	    try {
53	      await api.post('/api/auth/logout');
54	    } finally {
55	      setUser(null);
56	    }
57	  }, []);
58	
59	  return (
60	    <AuthContext.Provider value={{ user, loading, error, setError, login, logout }}>
61	      {children}
62	    </AuthContext.Provider>
63	  );
64	}
65	
66	/** Hook — throws if used outside <AuthProvider>. */
67	export function useAuth() {
68	  const ctx = useContext(AuthContext);
69	  if (!ctx) throw new Error('useAuth must be used inside <AuthProvider>');
70	  return ctx;
71	}
