8	import jakarta.servlet.http.HttpSession;
9	import jakarta.validation.Valid;
10	import org.springframework.http.ResponseEntity;
11	import org.springframework.security.authentication.BadCredentialsException;
12	import org.springframework.security.core.annotation.AuthenticationPrincipal;
13	import org.springframework.security.core.context.SecurityContext;
14	import org.springframework.security.core.context.SecurityContextHolder;
15	import org.springframework.security.core.context.SecurityContextHolderStrategy;
16	import org.springframework.security.authentication.UsernamePasswordAuthenticationToken;
17	import org.springframework.security.web.context.SecurityContextRepository;
18	import org.springframework.security.web.csrf.CsrfToken;
19	import org.springframework.web.bind.annotation.*;
20	
21	import java.util.Map;
22	
23	@RestController
24	@RequestMapping("/api/auth")
25	public class AuthController {
26	
27	    private final AuthService authService;
28	    private final UserRepository userRepository;
29	    private final SecurityContextRepository securityContextRepository;
30	    private final SecurityContextHolderStrategy securityContextHolderStrategy =
31	            SecurityContextHolder.getContextHolderStrategy();
32	
33	    public AuthController(AuthService authService,
34	                          UserRepository userRepository,
35	                          SecurityContextRepository securityContextRepository) {
36	        this.authService = authService;
37	        this.userRepository = userRepository;
38	        this.securityContextRepository = securityContextRepository;
39	    }
40	
41	    // -----------------------------------------------------------------------
42	    // POST /api/auth/login
43	    // -----------------------------------------------------------------------
44	
45	    @PostMapping("/login")
46	    public ResponseEntity<LoginResponse> login(@Valid @RequestBody LoginRequest request,
47	                                               HttpServletRequest httpRequest,
48	                                               HttpServletResponse httpResponse) {
49	        ReslifeUserDetails userDetails = authService.login(request, httpRequest);
50	
51	        // Build a fully authenticated token and store it in a new security context.
52	        // We explicitly save to the session via SecurityContextRepository so that
53	        // Spring Security's session-persistence machinery picks it up correctly in
54	        // Spring Security 6 (where just setting the holder is not always sufficient).
55	        UsernamePasswordAuthenticationToken authentication =
56	                UsernamePasswordAuthenticationToken.authenticated(
57	                        userDetails, null, userDetails.getAuthorities());
58	
59	        SecurityContext context = securityContextHolderStrategy.createEmptyContext();
60	        context.setAuthentication(authentication);
61	        securityContextHolderStrategy.setContext(context);
62	        securityContextRepository.saveContext(context, httpRequest, httpResponse);
63	
64	        User user = userRepository.findById(userDetails.getUserId())
65	                .orElseThrow(() -> new BadCredentialsException("Invalid credentials"));
66	
67	        return ResponseEntity.ok(LoginResponse.from(user));
68	    }
69	
70	    // -----------------------------------------------------------------------
71	    // POST /api/auth/logout
72	    // -----------------------------------------------------------------------
73	
74	    @PostMapping("/logout")
75	    public ResponseEntity<Void> logout(@AuthenticationPrincipal ReslifeUserDetails principal,
76	                                       HttpServletRequest httpRequest) {
77	        if (principal != null) {
78	            authService.recordLogout(principal, httpRequest);
79	        }
80	
81	        SecurityContextHolder.clearContext();
82	        HttpSession session = httpRequest.getSession(false);
83	        if (session != null) {
84	            session.invalidate();
85	        }
86	
87	        return ResponseEntity.noContent().build();
88	    }
89	
90	    // -----------------------------------------------------------------------
91	    // GET /api/auth/csrf  (public)
92	    // Forces the CookieCsrfTokenRepository to write the XSRF-TOKEN cookie.
93	    // The React SPA calls this once on startup so it has the token available
94	    // for subsequent POST/PATCH/DELETE requests.
95	    // -----------------------------------------------------------------------
96	
97	    @GetMapping("/csrf")
98	    public ResponseEntity<Map<String, String>> csrf(CsrfToken csrfToken) {
99	        // Accessing csrfToken causes CookieCsrfTokenRepository to write the cookie
100	        return ResponseEntity.ok(Map.of(
101	                "headerName", csrfToken.getHeaderName(),
102	                "parameterName", csrfToken.getParameterName()
103	        ));
104	    }
105	
106	    // -----------------------------------------------------------------------
107	    // GET /api/auth/me
108	    // -----------------------------------------------------------------------
109	
110	    @GetMapping("/me")
111	    public ResponseEntity<LoginResponse> currentUser(
112	            @AuthenticationPrincipal ReslifeUserDetails principal) {
113	
114	        User user = userRepository.findById(principal.getUserId())
115	                .orElseThrow(() -> new BadCredentialsException("Invalid credentials"));
116	
117	        return ResponseEntity.ok(LoginResponse.from(user));
118	    }
119	}
