1	package com.reslife.api.domain.resident;
2	
3	import com.reslife.api.domain.housing.CheckInStatus;
4	import com.reslife.api.domain.housing.MoveInRecord;
5	import com.reslife.api.domain.housing.MoveInRecordRepository;
6	import com.reslife.api.domain.housing.MoveInRecordRequest;
7	import jakarta.persistence.EntityNotFoundException;
8	import org.springframework.data.domain.Page;
9	import org.springframework.data.domain.Pageable;
10	import org.springframework.data.jpa.domain.Specification;
11	import org.springframework.stereotype.Service;
12	import org.springframework.transaction.annotation.Transactional;
13	
14	import java.util.ArrayList;
15	import java.util.List;
16	import java.util.UUID;
17	
18	@Service
19	@Transactional(readOnly = true)
20	public class ResidentService {
21	
22	    private final ResidentRepository          residentRepository;
23	    private final EmergencyContactRepository  emergencyContactRepository;
24	    private final MoveInRecordRepository      moveInRecordRepository;
25	
26	    public ResidentService(ResidentRepository residentRepository,
27	                           EmergencyContactRepository emergencyContactRepository,
28	                           MoveInRecordRepository moveInRecordRepository) {
29	        this.residentRepository         = residentRepository;
30	        this.emergencyContactRepository = emergencyContactRepository;
31	        this.moveInRecordRepository     = moveInRecordRepository;
32	    }
33	
34	    // ── Directory ─────────────────────────────────────────────────────────────
35	
36	    public Page<Resident> findAll(Pageable pageable) {
37	        return residentRepository.findAll(pageable);
38	    }
39	
40	    public Page<Resident> search(String q, String building, Integer classYear,
41	                                 CheckInStatus moveInStatus, Pageable pageable) {
42	        Specification<Resident> spec = Specification
43	                .where(ResidentSpec.withSearch(q))
44	                .and(ResidentSpec.withBuilding(building))
45	                .and(ResidentSpec.withClassYear(classYear))
46	                .and(ResidentSpec.withMoveInStatus(moveInStatus));
47	        return residentRepository.findAll(spec, pageable);
48	    }
49	
50	    public FilterOptionsResponse filterOptions() {
51	        return new FilterOptionsResponse(
52	                residentRepository.findDistinctBuildingNames(),
53	                residentRepository.findDistinctClassYears()
54	        );
55	    }
56	
57	    // ── Lookups ───────────────────────────────────────────────────────────────
58	
59	    public Resident findById(UUID id) {
60	        return residentRepository.findById(id)
61	                .orElseThrow(() -> new EntityNotFoundException("Resident not found: " + id));
62	    }
63	
64	    public Resident findByStudentId(String studentId) {
65	        return residentRepository.findByStudentId(studentId)
66	                .orElseThrow(() -> new EntityNotFoundException(
67	                        "Resident not found with studentId: " + studentId));
68	    }
69	
70	    // ── Create ────────────────────────────────────────────────────────────────
71	
72	    /**
73	     * Creates a new resident.
74	     *
75	     * @param force  when {@code true}, skips the duplicate pre-check and proceeds
76	     *               regardless of potential matches (caller has acknowledged the warning)
77	     * @throws DuplicateResidentException when duplicates are found and {@code force} is false
78	     * @throws IllegalArgumentException   when the email is already in use by a different resident
79	     */
80	    @Transactional
81	    public Resident create(ResidentRequest req, boolean force) {
82	        if (!force) {
83	            DuplicateCheckResponse dupes = checkDuplicates(
84	                    req.firstName(), req.lastName(), req.email(), req.studentId(), null);
85	            if (dupes.hasDuplicates()) {
86	                throw new DuplicateResidentException(dupes);
87	            }
88	        }
89	
90	        if (residentRepository.existsByEmail(req.email())) {
91	            throw new IllegalArgumentException("Email address is already in use");
92	        }
93	        if (req.studentId() != null && !req.studentId().isBlank()
94	                && residentRepository.existsByStudentId(req.studentId())) {
95	            throw new IllegalArgumentException("Student ID is already in use");
96	        }
97	
98	        Resident resident = new Resident();
99	        applyRequest(resident, req);
100	        return residentRepository.save(resident);
101	    }
102	
103	    // ── Update ────────────────────────────────────────────────────────────────
104	
105	    @Transactional
106	    public Resident update(UUID id, ResidentRequest req) {
107	        Resident resident = findById(id);
108	
109	        if (residentRepository.existsByEmailIgnoreCaseAndIdNot(req.email(), id)) {
110	            throw new IllegalArgumentException("Email address is already in use");
111	        }
112	        if (req.studentId() != null && !req.studentId().isBlank()
113	                && residentRepository.existsByStudentIdAndIdNot(req.studentId(), id)) {
114	            throw new IllegalArgumentException("Student ID is already in use");
115	        }
116	
117	        applyRequest(resident, req);
118	        return residentRepository.save(resident);
119	    }
120	
121	    private void applyRequest(Resident r, ResidentRequest req) {
122	        r.setFirstName(req.firstName());
123	        r.setLastName(req.lastName());
124	        r.setEmail(req.email());
125	        r.setPhone(req.phone());
126	        r.setStudentId(req.studentId());
127	        r.setDateOfBirth(req.dateOfBirth());
128	        r.setEnrollmentStatus(req.enrollmentStatus());
129	        r.setDepartment(req.department());
130	        r.setClassYear(req.classYear());
131	        r.setRoomNumber(req.roomNumber());
132	        r.setBuildingName(req.buildingName());
133	    }
134	
135	    // ── Duplicate detection ───────────────────────────────────────────────────
136	
137	    /**
138	     * Checks whether any existing residents might be duplicates.
139	     *
140	     * <p>Three signals are checked independently:
141	     * <ol>
142	     *   <li><b>email</b>   — exact case-insensitive match (unique in DB, at most 1 hit)</li>
143	     *   <li><b>studentId</b> — exact match</li>
144	     *   <li><b>name</b>    — same first + last name, case-insensitive</li>
145	     * </ol>
146	     * Each matching resident appears at most once in the list (earliest signal wins).
147	     *
148	     * @param excludeId  when editing an existing record, pass its ID so it is
149	     *                   not reported as its own duplicate
150	     */
151	    public DuplicateCheckResponse checkDuplicates(
152	            String firstName, String lastName, String email, String studentId, UUID excludeId) {
153	
154	        List<DuplicateCheckResponse.Candidate> candidates = new ArrayList<>();
155	
156	        if (email != null && !email.isBlank()) {
157	            residentRepository.findByEmailIgnoreCase(email.trim()).ifPresent(r -> {
158	                if (excludeId == null || !r.getId().equals(excludeId)) {
159	                    candidates.add(candidate(r, "email"));
160	                }
161	            });
162	        }
163	
164	        if (studentId != null && !studentId.isBlank()) {
165	            residentRepository.findByStudentId(studentId.trim()).ifPresent(r -> {
166	                if ((excludeId == null || !r.getId().equals(excludeId))
167	                        && noneMatch(candidates, r.getId())) {
168	                    candidates.add(candidate(r, "studentId"));
169	                }
170	            });
171	        }
172	
173	        if (firstName != null && !firstName.isBlank()
174	                && lastName != null && !lastName.isBlank()) {
175	            residentRepository
176	                    .findByFirstNameIgnoreCaseAndLastNameIgnoreCase(firstName.trim(), lastName.trim())
177	                    .stream()
178	                    .filter(r -> excludeId == null || !r.getId().equals(excludeId))
179	                    .filter(r -> noneMatch(candidates, r.getId()))
180	                    .forEach(r -> candidates.add(candidate(r, "name")));
181	        }
182	
183	        return new DuplicateCheckResponse(candidates);
184	    }
185	
186	    private static DuplicateCheckResponse.Candidate candidate(Resident r, String reason) {
187	        return new DuplicateCheckResponse.Candidate(
188	                r.getId(), r.getStudentId(), r.getFirstName(), r.getLastName(), r.getEmail(), reason);
189	    }
190	
191	    private static boolean noneMatch(List<DuplicateCheckResponse.Candidate> list, UUID id) {
192	        return list.stream().noneMatch(c -> c.id().equals(id));
193	    }
194	
195	    // ── Emergency contacts ────────────────────────────────────────────────────
196	
197	    public List<EmergencyContact> findEmergencyContacts(UUID residentId) {
198	        findById(residentId); // verify resident exists
199	        return emergencyContactRepository.findByResidentId(residentId);
200	    }
201	
202	    @Transactional
203	    public EmergencyContact addEmergencyContact(UUID residentId, EmergencyContactRequest req) {
204	        Resident resident = findById(residentId);
205	        // Only one primary contact allowed
206	        if (req.primary()) {
207	            emergencyContactRepository.findByResidentIdAndPrimaryTrue(residentId)
208	                    .forEach(c -> { c.setPrimary(false); emergencyContactRepository.save(c); });
209	        }
210	        EmergencyContact ec = new EmergencyContact();
211	        ec.setResident(resident);
212	        applyContactRequest(ec, req);
213	        return emergencyContactRepository.save(ec);
214	    }
215	
216	    @Transactional
217	    public EmergencyContact updateEmergencyContact(UUID residentId, UUID contactId,
218	                                                    EmergencyContactRequest req) {
219	        EmergencyContact ec = emergencyContactRepository.findById(contactId)
220	                .orElseThrow(() -> new EntityNotFoundException(
221	                        "Emergency contact not found: " + contactId));
222	        if (!ec.getResident().getId().equals(residentId)) {
223	            throw new IllegalArgumentException("Contact does not belong to resident " + residentId);
224	        }
225	        if (req.primary() && !ec.isPrimary()) {
226	            emergencyContactRepository.findByResidentIdAndPrimaryTrue(residentId)
227	                    .forEach(c -> { c.setPrimary(false); emergencyContactRepository.save(c); });
228	        }
229	        applyContactRequest(ec, req);
230	        return emergencyContactRepository.save(ec);
231	    }
232	
233	    @Transactional
234	    public void removeEmergencyContact(UUID residentId, UUID contactId) {
235	        EmergencyContact ec = emergencyContactRepository.findById(contactId)
236	                .orElseThrow(() -> new EntityNotFoundException(
237	                        "Emergency contact not found: " + contactId));
238	        if (!ec.getResident().getId().equals(residentId)) {
239	            throw new IllegalArgumentException("Contact does not belong to resident " + residentId);
240	        }
241	        emergencyContactRepository.delete(ec);
242	    }
243	
244	    private void applyContactRequest(EmergencyContact ec, EmergencyContactRequest req) {
245	        ec.setName(req.name());
246	        ec.setRelationship(req.relationship());
247	        ec.setPhone(req.phone());
248	        ec.setEmail(req.email());
249	        ec.setPrimary(req.primary());
250	    }
251	
252	    // ── Move-in records ───────────────────────────────────────────────────────
253	
254	    public List<MoveInRecord> findMoveInRecords(UUID residentId) {
255	        findById(residentId);
256	        return moveInRecordRepository.findByResidentId(residentId);
257	    }
258	
259	    @Transactional
260	    public MoveInRecord addMoveInRecord(UUID residentId, MoveInRecordRequest req) {
261	        Resident resident = findById(residentId);
262	        MoveInRecord record = new MoveInRecord();
263	        record.setResident(resident);
264	        applyMoveInRequest(record, req);
265	        MoveInRecord saved = moveInRecordRepository.save(record);
266	        // Sync current room on the resident
267	        resident.setRoomNumber(record.getRoomNumber());
268	        resident.setBuildingName(record.getBuildingName());
269	        residentRepository.save(resident);
270	        return saved;
271	    }
272	
273	    @Transactional
274	    public MoveInRecord updateMoveInRecord(UUID residentId, UUID recordId, MoveInRecordRequest req) {
275	        MoveInRecord record = moveInRecordRepository.findById(recordId)
276	                .orElseThrow(() -> new EntityNotFoundException(
277	                        "Move-in record not found: " + recordId));
278	        if (!record.getResident().getId().equals(residentId)) {
279	            throw new IllegalArgumentException(
280	                    "Move-in record does not belong to resident " + residentId);
281	        }
282	        applyMoveInRequest(record, req);
283	        return moveInRecordRepository.save(record);
284	    }
285	
286	    private void applyMoveInRequest(MoveInRecord r, MoveInRecordRequest req) {
287	        r.setRoomNumber(req.roomNumber());
288	        r.setBuildingName(req.buildingName());
289	        r.setMoveInDate(req.moveInDate());
290	        r.setMoveOutDate(req.moveOutDate());
291	        r.setCheckInStatus(req.checkInStatus() != null
292	                ? req.checkInStatus()
293	                : com.reslife.api.domain.housing.CheckInStatus.PENDING);
294	        r.setNotes(req.notes());
295	    }
296	
297	    // ── Soft delete ───────────────────────────────────────────────────────────
298	
299	    @Transactional
300	    public Resident save(Resident resident) {
301	        return residentRepository.save(resident);
302	    }
303	
304	    @Transactional
305	    public void softDelete(UUID id) {
306	        Resident resident = findById(id);
307	        resident.softDelete();
308	        residentRepository.save(resident);
309	    }
310	
311	    /** @deprecated kept for backward compat with HousingService — use addMoveInRecord */
312	    @Transactional
313	    public EmergencyContact addEmergencyContact(UUID residentId, EmergencyContact contact) {
314	        Resident resident = findById(residentId);
315	        contact.setResident(resident);
316	        return emergencyContactRepository.save(contact);
317	    }
318	}
