5	import org.springframework.security.core.GrantedAuthority;
6	import org.springframework.security.core.authority.SimpleGrantedAuthority;
7	import org.springframework.security.core.userdetails.UserDetails;
8	
9	import java.io.Serial;
10	import java.io.Serializable;
11	import java.util.Collection;
12	import java.util.Set;
13	import java.util.UUID;
14	import java.util.stream.Collectors;
15	
16	/**
17	 * Serializable Spring Security principal stored in the HTTP session.
18	 * Holds only the data needed for security decisions — no JPA proxies.
19	 */
20	public final class ReslifeUserDetails implements UserDetails, Serializable {
21	
22	    @Serial
23	    private static final long serialVersionUID = 1L;
24	
25	    private final UUID userId;
26	    private final String username;
27	    private final String passwordHash;
28	    private final AccountStatus accountStatus;
29	    private final Set<SimpleGrantedAuthority> authorities;
30	
31	    private ReslifeUserDetails(UUID userId, String username, String passwordHash,
32	                                AccountStatus accountStatus,
33	                                Set<SimpleGrantedAuthority> authorities) {
34	        this.userId = userId;
35	        this.username = username;
36	        this.passwordHash = passwordHash;
37	        this.accountStatus = accountStatus;
38	        this.authorities = authorities;
39	    }
40	
41	    public static ReslifeUserDetails from(User user) {
42	        Set<SimpleGrantedAuthority> authorities = user.getUserRoles().stream()
43	                .map(ur -> new SimpleGrantedAuthority("ROLE_" + ur.getRole().getName().name()))
44	                .collect(Collectors.toSet());
45	
46	        return new ReslifeUserDetails(
47	                user.getId(),
48	                user.getUsername(),
49	                user.getPasswordHash(),
50	                user.getAccountStatus(),
51	                authorities
52	        );
53	    }
54	
55	    public UUID getUserId() {
56	        return userId;
57	    }
58	
59	    public AccountStatus getAccountStatus() {
60	        return accountStatus;
61	    }
62	
63	    // -----------------------------------------------------------------------
64	    // UserDetails contract
65	    // -----------------------------------------------------------------------
66	
67	    @Override
68	    public Collection<? extends GrantedAuthority> getAuthorities() {
69	        return authorities;
70	    }
71	
72	    @Override
73	    public String getPassword() {
74	        return passwordHash;
75	    }
76	
77	    @Override
78	    public String getUsername() {
79	        return username;
80	    }
81	
82	    /** An account that is not ACTIVE is considered "disabled" for Spring Security purposes. */
83	    @Override
84	    public boolean isEnabled() {
85	        return accountStatus == AccountStatus.ACTIVE;
86	    }
87	
88	    /** BLACKLISTED and FROZEN accounts are considered locked. */
89	    @Override
90	    public boolean isAccountNonLocked() {
91	        return accountStatus != AccountStatus.BLACKLISTED && accountStatus != AccountStatus.FROZEN;
92	    }
93	
94	    @Override
95	    public boolean isAccountNonExpired() {
96	        return true;
97	    }
98	
99	    @Override
100	    public boolean isCredentialsNonExpired() {
101	        return true;
102	    }
103	}
