4	import com.reslife.api.domain.integration.RateLimitExceededException;
5	import com.reslife.api.domain.messaging.BlockedException;
6	import com.reslife.api.domain.resident.DuplicateCheckResponse;
7	import com.reslife.api.domain.resident.DuplicateResidentException;
8	import jakarta.persistence.EntityNotFoundException;
9	import org.slf4j.Logger;
10	import org.slf4j.LoggerFactory;
11	import org.springframework.http.HttpStatus;
12	import org.springframework.http.ResponseEntity;
13	import org.springframework.security.authentication.BadCredentialsException;
14	import org.springframework.validation.FieldError;
15	import org.springframework.web.bind.MethodArgumentNotValidException;
16	import org.springframework.web.bind.annotation.ExceptionHandler;
17	import org.springframework.web.bind.annotation.RestControllerAdvice;
18	import org.springframework.web.multipart.MaxUploadSizeExceededException;
19	
20	import java.util.List;
21	
22	/**
23	 * Translates exceptions into consistent {@link ApiError} JSON responses.
24	 *
25	 * <p>Auth-related Spring Security exceptions ({@code AuthenticationException},
26	 * {@code AccessDeniedException}) are NOT handled here — they never reach a
27	 * {@code @ExceptionHandler} because Spring Security's filter chain intercepts
28	 * them first and the custom entry points in {@code SecurityConfig} handle them.
29	 *
30	 * <p>The only auth exception that DOES reach here is {@link BadCredentialsException}
31	 * thrown explicitly from {@code AuthService} within the controller call stack.
32	 */
33	@RestControllerAdvice
34	public class GlobalExceptionHandler {
35	
36	    private static final Logger log = LoggerFactory.getLogger(GlobalExceptionHandler.class);
37	
38	    /**
39	     * Possible duplicate residents on create — returns 409 with the candidate list
40	     * so the frontend can show a "save anyway?" confirmation.
41	     */
42	    @ExceptionHandler(DuplicateResidentException.class)
43	    public ResponseEntity<DuplicateCheckResponse> handleDuplicateResident(
44	            DuplicateResidentException ex) {
45	        return ResponseEntity.status(HttpStatus.CONFLICT).body(ex.getDuplicates());
46	    }
47	
48	    /** Recipient has blocked the sender from starting new threads. */
49	    @ExceptionHandler(BlockedException.class)
50	    public ResponseEntity<ApiError> handleBlocked(BlockedException ex) {
51	        return ResponseEntity
52	                .status(HttpStatus.FORBIDDEN)
53	                .body(ApiError.of(403, "Forbidden", ex.getMessage()));
54	    }
55	
56	    /** Login failures — always the same generic message regardless of reason. */
57	    @ExceptionHandler(BadCredentialsException.class)
58	    public ResponseEntity<ApiError> handleBadCredentials(BadCredentialsException ex) {
59	        // Never echo ex.getMessage() — it may contain implementation details.
60	        return ResponseEntity
61	                .status(HttpStatus.UNAUTHORIZED)
62	                .body(ApiError.of(401, "Unauthorized", "Invalid credentials"));
63	    }
64	
65	    /**
66	     * Multipart file exceeds Spring's configured limit (thrown before reaching our code).
67	     * Returns 413 so the browser/client gets a meaningful status.
68	     */
69	    @ExceptionHandler(MaxUploadSizeExceededException.class)
70	    public ResponseEntity<ApiError> handleMaxUploadSize(MaxUploadSizeExceededException ex) {
71	        return ResponseEntity
72	                .status(HttpStatus.PAYLOAD_TOO_LARGE)
73	                .body(ApiError.of(413, "Payload Too Large",
74	                        "File exceeds the maximum allowed size of 15 MB"));
75	    }
76	
77	    /** Resource not found. */
78	    @ExceptionHandler(EntityNotFoundException.class)
79	    public ResponseEntity<ApiError> handleNotFound(EntityNotFoundException ex) {
80	        return ResponseEntity
81	                .status(HttpStatus.NOT_FOUND)
82	                .body(ApiError.of(404, "Not Found", ex.getMessage()));
83	    }
84	
85	    /** Constraint violations from request body validation (@Valid). */
86	    @ExceptionHandler(MethodArgumentNotValidException.class)
87	    public ResponseEntity<ApiError> handleValidation(MethodArgumentNotValidException ex) {
88	        List<ApiError.FieldError> fieldErrors = ex.getBindingResult()
89	                .getFieldErrors()
90	                .stream()
91	                .map(fe -> new ApiError.FieldError(fe.getField(), fe.getDefaultMessage()))
92	                .toList();
93	
94	        return ResponseEntity
95	                .status(HttpStatus.BAD_REQUEST)
96	                .body(ApiError.withFieldErrors(400, "Bad Request",
97	                        "Validation failed", fieldErrors));
98	    }
99	
100	    /**
101	     * HMAC signature failure or stale timestamp on integration requests.
102	     * Note: for requests that reach the filter these are handled there directly;
103	     * this handler covers any edge case where they propagate to Spring MVC.
104	     */
105	    @ExceptionHandler(InvalidSignatureException.class)
106	    public ResponseEntity<ApiError> handleInvalidSignature(InvalidSignatureException ex) {
107	        return ResponseEntity
108	                .status(HttpStatus.UNAUTHORIZED)
109	                .body(ApiError.of(401, "Unauthorized", ex.getMessage()));
110	    }
111	
112	    /** Integration key has exceeded its per-minute request quota. */
113	    @ExceptionHandler(RateLimitExceededException.class)
114	    public ResponseEntity<ApiError> handleRateLimit(RateLimitExceededException ex) {
115	        return ResponseEntity
116	                .status(HttpStatus.TOO_MANY_REQUESTS)
117	                .header("Retry-After", "60")
118	                .body(ApiError.of(429, "Too Many Requests", ex.getMessage()));
119	    }
120	
121	    /** Illegal arguments from service layer (e.g. admin trying to change own status). */
122	    @ExceptionHandler(IllegalArgumentException.class)
123	    public ResponseEntity<ApiError> handleIllegalArgument(IllegalArgumentException ex) {
124	        return ResponseEntity
125	                .status(HttpStatus.UNPROCESSABLE_ENTITY)
126	                .body(ApiError.of(422, "Unprocessable Entity", ex.getMessage()));
127	    }
128	
129	    /** Catch-all — log the full stack trace server-side but return a safe message. */
130	    @ExceptionHandler(Exception.class)
131	    public ResponseEntity<ApiError> handleGeneric(Exception ex) {
132	        log.error("Unhandled exception", ex);
133	        return ResponseEntity
134	                .status(HttpStatus.INTERNAL_SERVER_ERROR)
135	                .body(ApiError.of(500, "Internal Server Error",
136	                        "An unexpected error occurred"));
137	    }
138	}
