1	package com.reslife.api.domain.integration;
2	
3	import jakarta.servlet.FilterChain;
4	import jakarta.servlet.ServletException;
5	import jakarta.servlet.http.HttpServletRequest;
6	import jakarta.servlet.http.HttpServletResponse;
7	import org.slf4j.Logger;
8	import org.slf4j.LoggerFactory;
9	import org.springframework.http.HttpStatus;
10	import org.springframework.http.MediaType;
11	import org.springframework.util.AntPathMatcher;
12	import org.springframework.web.filter.OncePerRequestFilter;
13	
14	import java.io.IOException;
15	import java.time.Instant;
16	
17	/**
18	 * Authenticates inbound requests to {@code /api/integrations/**} using HMAC-SHA256.
19	 *
20	 * <h3>Required headers</h3>
21	 * <pre>
22	 *   X-Integration-Key-ID  — the public key identifier (e.g. rk_abc123…)
23	 *   X-Reslife-Timestamp   — Unix epoch seconds (replay protection: ±5 min)
24	 *   X-Reslife-Signature   — sha256={HMAC-SHA256 of "{timestamp}\n{body}"}
25	 * </pre>
26	 *
27	 * <p>On success the resolved {@link IntegrationKey} is stored as a request attribute
28	 * ({@link #KEY_ATTR}) for use by the controller.  On failure the filter short-circuits
29	 * with an appropriate HTTP status code and writes a minimal JSON error body.
30	 *
31	 * <p>This class is not a {@code @Component} — it is registered as a Spring {@code @Bean}
32	 * in {@link com.reslife.api.config.IntegrationConfig} and injected into the Spring Security
33	 * filter chain, preventing double registration as both a servlet filter and a security filter.
34	 */
35	public class IntegrationAuthFilter extends OncePerRequestFilter {
36	
37	    /** Request attribute key under which the authenticated {@link IntegrationKey} is stored. */
38	    public static final String KEY_ATTR   = "integration.key";
39	    public static final String KEY_ID_HDR = "X-Integration-Key-ID";
40	    public static final String TS_HDR     = "X-Reslife-Timestamp";
41	    public static final String SIG_HDR    = "X-Reslife-Signature";
42	
43	    private static final Logger          log     = LoggerFactory.getLogger(IntegrationAuthFilter.class);
44	    private static final AntPathMatcher  MATCHER = new AntPathMatcher();
45	
46	    private final IntegrationKeyRepository     keyRepo;
47	    private final HmacService                  hmacService;
48	    private final IntegrationRateLimiter       rateLimiter;
49	    private final IntegrationAuditLogRepository auditRepo;
50	
51	    public IntegrationAuthFilter(IntegrationKeyRepository keyRepo,
52	                                  HmacService hmacService,
53	                                  IntegrationRateLimiter rateLimiter,
54	                                  IntegrationAuditLogRepository auditRepo) {
55	        this.keyRepo     = keyRepo;
56	        this.hmacService = hmacService;
57	        this.rateLimiter = rateLimiter;
58	        this.auditRepo   = auditRepo;
59	    }
60	
61	    @Override
62	    protected boolean shouldNotFilter(HttpServletRequest request) {
63	        String path = request.getRequestURI().substring(request.getContextPath().length());
64	        return !MATCHER.match("/api/integrations/**", path);
65	    }
66	
67	    @Override
68	    protected void doFilterInternal(HttpServletRequest request,
69	                                     HttpServletResponse response,
70	                                     FilterChain chain)
71	            throws ServletException, IOException {
72	
73	        // Buffer body so the controller can also read it
74	        CachedBodyHttpServletRequest wrapped = new CachedBodyHttpServletRequest(request);
75	        byte[] body = wrapped.getCachedBody();
76	
77	        String keyIdHeader = request.getHeader(KEY_ID_HDR);
78	        String tsHeader    = request.getHeader(TS_HDR);
79	        String sigHeader   = request.getHeader(SIG_HDR);
80	        String requestId   = request.getHeader("X-Request-ID");
81	        String sourceIp    = request.getRemoteAddr();
82	
83	        if (keyIdHeader == null || tsHeader == null || sigHeader == null) {
84	            reject(response, HttpStatus.UNAUTHORIZED,
85	                    "Missing required headers: " + KEY_ID_HDR + ", " + TS_HDR + ", " + SIG_HDR);
86	            return;
87	        }
88	
89	        // Key lookup
90	        IntegrationKey key = keyRepo.findByKeyIdAndActiveTrue(keyIdHeader).orElse(null);
91	        if (key == null) {
92	            reject(response, HttpStatus.UNAUTHORIZED, "Unknown or revoked integration key");
93	            return;
94	        }
95	
96	        // Rate limit — checked before HMAC to prevent brute-force cost
97	        if (!rateLimiter.tryAcquire(keyIdHeader)) {
98	            audit(key, request.getRequestURI(), sourceIp, 429, false, "Rate limit exceeded", requestId);
99	            response.setHeader("Retry-After", "60");
100	            response.setHeader("X-RateLimit-Limit", String.valueOf(IntegrationRateLimiter.LIMIT));
101	            reject(response, HttpStatus.TOO_MANY_REQUESTS,
102	                    "Rate limit exceeded — " + IntegrationRateLimiter.LIMIT + " requests/minute");
103	            return;
104	        }
105	
106	        // Timestamp parse
107	        long timestamp;
108	        try {
109	            timestamp = Long.parseLong(tsHeader);
110	        } catch (NumberFormatException e) {
111	            audit(key, request.getRequestURI(), sourceIp, 401, false, "Invalid timestamp format", requestId);
112	            reject(response, HttpStatus.UNAUTHORIZED, "Invalid " + TS_HDR + " — must be Unix epoch seconds");
113	            return;
114	        }
115	
116	        // HMAC verification (also checks replay window)
117	        try {
118	            hmacService.verify(key.getSecret(), timestamp, body, sigHeader);
119	        } catch (InvalidSignatureException e) {
120	            audit(key, request.getRequestURI(), sourceIp, 401, false, e.getMessage(), requestId);
121	            reject(response, HttpStatus.UNAUTHORIZED, e.getMessage());
122	            return;
123	        }
124	
125	        // Update last-used timestamp (best-effort)
126	        try {
127	            key.setLastUsedAt(Instant.now());
128	            keyRepo.save(key);
129	        } catch (Exception e) {
130	            log.warn("Could not update lastUsedAt for key {}: {}", keyIdHeader, e.getMessage());
131	        }
132	
133	        wrapped.setAttribute(KEY_ATTR, key);
134	        chain.doFilter(wrapped, response);
135	    }
136	
137	    // ── Helpers ────────────────────────────────────────────────────────────
138	
139	    private void reject(HttpServletResponse response, HttpStatus status, String message)
140	            throws IOException {
141	        response.setStatus(status.value());
142	        response.setContentType(MediaType.APPLICATION_JSON_VALUE);
143	        // Escape any double-quotes in the message to keep JSON valid
144	        response.getWriter().write("{\"error\":\"" + message.replace("\"", "'") + "\"}");
145	    }
146	
147	    private void audit(IntegrationKey key, String path, String sourceIp,
148	                        int status, boolean success, String error, String requestId) {
149	        try {
150	            IntegrationAuditLog entry = new IntegrationAuditLog();
151	            entry.setIntegrationKey(key);
152	            entry.setDirection(IntegrationAuditLog.Direction.INBOUND);
153	            entry.setTargetUrl(path);
154	            entry.setSourceIp(sourceIp);
155	            entry.setHttpStatus(status);
156	            entry.setSuccess(success);
157	            entry.setErrorMessage(error);
158	            entry.setRequestId(requestId);
159	            auditRepo.save(entry);
160	        } catch (Exception e) {
161	            log.warn("Failed to write integration auth audit log", e);
162	        }
163	    }
164	}
