1	package com.reslife.api.config;
2	
3	import com.reslife.api.domain.integration.*;
4	import org.springframework.boot.web.servlet.FilterRegistrationBean;
5	import org.springframework.context.annotation.Bean;
6	import org.springframework.context.annotation.Configuration;
7	import org.springframework.http.client.SimpleClientHttpRequestFactory;
8	import org.springframework.web.client.ResponseErrorHandler;
9	import org.springframework.web.client.RestTemplate;
10	
11	/**
12	 * Infrastructure beans for the local integration layer:
13	 * <ul>
14	 *   <li>{@link IntegrationAuthFilter} — registered in the Spring Security filter chain
15	 *       (not as a standalone servlet filter, to prevent double execution)</li>
16	 *   <li>{@code webhookRestTemplate} — {@link RestTemplate} with 5 s connect / 10 s read
17	 *       timeouts and a no-op error handler so non-2xx responses are returned normally</li>
18	 * </ul>
19	 */
20	@Configuration
21	public class IntegrationConfig {
22	
23	    /**
24	     * The auth filter as a Spring bean so it can be injected into {@link SecurityConfig}.
25	     * The matching {@link FilterRegistrationBean} disables auto-registration as a
26	     * plain servlet filter, ensuring the filter runs only once (inside the security chain).
27	     */
28	    @Bean
29	    public IntegrationAuthFilter integrationAuthFilter(
30	            IntegrationKeyRepository keyRepo,
31	            HmacService hmacService,
32	            IntegrationRateLimiter rateLimiter,
33	            IntegrationAuditLogRepository auditRepo) {
34	        return new IntegrationAuthFilter(keyRepo, hmacService, rateLimiter, auditRepo);
35	    }
36	
37	    /** Prevents Spring Boot from auto-registering the filter as a plain servlet filter. */
38	    @Bean
39	    public FilterRegistrationBean<IntegrationAuthFilter> integrationAuthFilterRegistration(
40	            IntegrationAuthFilter filter) {
41	        FilterRegistrationBean<IntegrationAuthFilter> registration = new FilterRegistrationBean<>(filter);
42	        registration.setEnabled(false);
43	        return registration;
44	    }
45	
46	    /** RestTemplate used exclusively by {@link WebhookService} for outgoing webhook calls. */
47	    @Bean("webhookRestTemplate")
48	    public RestTemplate webhookRestTemplate() {
49	        SimpleClientHttpRequestFactory factory = new SimpleClientHttpRequestFactory();
50	        factory.setConnectTimeout(5_000);
51	        factory.setReadTimeout(10_000);
52	
53	        RestTemplate template = new RestTemplate(factory);
54	        // Never throw on non-2xx — let WebhookService inspect the status itself
55	        template.setErrorHandler(new ResponseErrorHandler() {
56	            @Override public boolean hasError(org.springframework.http.client.ClientHttpResponse r) { return false; }
57	            @Override public void    handleError(org.springframework.http.client.ClientHttpResponse r) {}
58	        });
59	        return template;
60	    }
61	}
