41	    // -----------------------------------------------------------------------
42	    // Account status management
43	    // -----------------------------------------------------------------------
44	
45	    /**
46	     * Changes a user's account status.
47	     *
48	     * <p>Rules:
49	     * <ul>
50	     *   <li>An admin cannot change their own account status.</li>
51	     *   <li>Disabling starts the 30-day purge clock.</li>
52	     *   <li>Re-activating cancels the purge clock.</li>
53	     *   <li>Any status change immediately kills all active sessions for the target user.</li>
54	     * </ul>
55	     */
56	    @Transactional
57	    public User updateAccountStatus(UUID targetUserId, AccountStatus newStatus, String reason,
58	                                    UUID actorUserId, HttpServletRequest httpRequest) {
59	        if (targetUserId.equals(actorUserId)) {
60	            throw new IllegalArgumentException("Administrators cannot change their own account status.");
61	        }
62	
63	        User target = userRepository.findById(targetUserId)
64	                .orElseThrow(() -> new EntityNotFoundException("User not found: " + targetUserId));
65	
66	        AccountStatus oldStatus = target.getAccountStatus();
67	
68	        target.setAccountStatus(newStatus);
69	        target.setStatusReason(reason);
70	        target.setStatusChangedBy(actorUserId);
71	        target.setStatusChangedAt(Instant.now());
72	
73	        switch (newStatus) {
74	            case DISABLED -> {
75	                // Start the 30-day purge clock only on first disable
76	                if (target.getScheduledPurgeAt() == null) {
77	                    target.setScheduledPurgeAt(Instant.now().plus(30, ChronoUnit.DAYS));
78	                }
79	            }
80	            case ACTIVE -> {
81	                // Re-activation cancels any scheduled purge
82	                target.setScheduledPurgeAt(null);
83	            }
84	            default -> { /* FROZEN and BLACKLISTED: no purge clock change */ }
85	        }
86	
87	        userRepository.save(target);
88	
89	        // Immediately expire all active sessions for the affected user
90	        invalidateUserSessions(target.getUsername());
91	
92	        // Audit the action
93	        String ip = extractClientIp(httpRequest);
94	        String ua = httpRequest.getHeader("User-Agent");
95	        auditStatusChange(target, oldStatus, newStatus, reason, actorUserId, ip, ua);
96	
97	        return target;
98	    }
