105	     * Soft-deletes a user account and schedules it for permanent purge in 30 days.
106	     *
107	     * <p>Unlike {@link #updateAccountStatus}, this is a one-way operation:
108	     * the account is immediately soft-deleted ({@code deleted_at} set) so the
109	     * nightly purge job can find and permanently remove it when the grace period
110	     * expires. All active sessions are invalidated and the action is audit-logged.
111	     */
112	    @Transactional
113	    public void deleteAccount(UUID targetUserId, UUID actorUserId, HttpServletRequest httpRequest) {
114	        if (targetUserId.equals(actorUserId)) {
115	            throw new IllegalArgumentException("Administrators cannot delete their own account.");
116	        }
117	
118	        User target = userRepository.findById(targetUserId)
119	                .orElseThrow(() -> new EntityNotFoundException("User not found: " + targetUserId));
120	
121	        target.softDelete();
122	        target.setScheduledPurgeAt(Instant.now().plus(30, ChronoUnit.DAYS));
123	        target.setAccountStatus(AccountStatus.DISABLED);
124	        target.setStatusChangedBy(actorUserId);
125	        target.setStatusChangedAt(Instant.now());
126	
127	        userRepository.save(target);
128	
129	        invalidateUserSessions(target.getUsername());
130	
131	        User actor = userRepository.findById(actorUserId).orElse(null);
