2	
3	import jakarta.annotation.PostConstruct;
4	import jakarta.persistence.EntityNotFoundException;
5	import org.slf4j.Logger;
6	import org.slf4j.LoggerFactory;
7	import org.springframework.beans.factory.annotation.Value;
8	import org.springframework.core.io.FileSystemResource;
9	import org.springframework.core.io.Resource;
10	import org.springframework.stereotype.Service;
11	import org.springframework.web.multipart.MultipartFile;
12	
13	import java.io.IOException;
14	import java.io.InputStream;
15	import java.io.UncheckedIOException;
16	import java.nio.file.*;
17	import java.util.UUID;
18	
19	/**
20	 * Manages physical file storage on the local filesystem.
21	 *
22	 * <p>Directory layout:
23	 * <pre>{upload-dir}/{agreementId}/{storedFilename}</pre>
24	 *
25	 * <p>Only server-generated filenames are ever used in path operations —
26	 * user-supplied filenames are stored as metadata only and never used
27	 * in filesystem paths.
28	 */
29	@Service
30	public class StorageService {
31	
32	    private static final Logger log = LoggerFactory.getLogger(StorageService.class);
33	
34	    private final Path rootDir;
35	
36	    public StorageService(@Value("${app.storage.upload-dir}") String uploadDir) {
37	        this.rootDir = Paths.get(uploadDir).toAbsolutePath().normalize();
38	    }
39	
40	    @PostConstruct
41	    public void init() {
42	        try {
43	            Files.createDirectories(rootDir);
44	            log.info("File storage root: {}", rootDir);
45	        } catch (IOException e) {
46	            throw new UncheckedIOException("Cannot create storage directory: " + rootDir, e);
47	        }
48	    }
49	
50	    /**
51	     * Persists a multipart upload to disk.
52	     *
53	     * @param agreementId   used as the subdirectory name
54	     * @param storedFilename server-generated {@code UUID.ext}
55	     * @param file          the uploaded multipart part
56	     */
57	    public void store(UUID agreementId, String storedFilename, MultipartFile file) {
58	        Path target = safeResolve(agreementId.toString(), storedFilename);
59	        try {
60	            Files.createDirectories(target.getParent());
61	            try (InputStream in = file.getInputStream()) {
62	                Files.copy(in, target, StandardCopyOption.REPLACE_EXISTING);
63	            }
64	        } catch (IOException e) {
65	            throw new UncheckedIOException("Failed to store file " + storedFilename, e);
66	        }
67	    }
68	
69	    /**
70	     * Returns a {@link Resource} for streaming the file to the client.
71	     *
72	     * @throws EntityNotFoundException if the file does not exist on disk
73	     */
74	    public Resource load(UUID agreementId, String storedFilename) {
75	        Path file = safeResolve(agreementId.toString(), storedFilename);
76	        Resource resource = new FileSystemResource(file);
77	        if (!resource.exists() || !resource.isReadable()) {
78	            throw new EntityNotFoundException(
79	                    "File not found on disk: " + storedFilename);
80	        }
81	        return resource;
82	    }
83	
84	    /**
85	     * Deletes the stored file.  Logs a warning on failure instead of
86	     * propagating — the DB record is already deleted at this point.
87	     */
88	    public void delete(UUID agreementId, String storedFilename) {
89	        try {
90	            Path file = safeResolve(agreementId.toString(), storedFilename);
91	            Files.deleteIfExists(file);
92	        } catch (IOException e) {
93	            log.warn("Could not delete stored file {} for agreement {}: {}",
94	                    storedFilename, agreementId, e.getMessage());
95	        }
96	    }
97	
98	    // ── Message images ────────────────────────────────────────────────────────
99	
100	    /**
101	     * Stores a message image under {@code {rootDir}/messages/{storedFilename}}.
102	     *
103	     * @param storedFilename server-generated filename (UUID.ext)
104	     */
105	    public void storeMessageImage(String storedFilename, MultipartFile file) {
106	        Path target = safeResolve("messages", storedFilename);
107	        try {
108	            Files.createDirectories(target.getParent());
109	            try (InputStream in = file.getInputStream()) {
110	                Files.copy(in, target, StandardCopyOption.REPLACE_EXISTING);
111	            }
112	        } catch (IOException e) {
113	            throw new UncheckedIOException("Failed to store message image " + storedFilename, e);
114	        }
115	    }
116	
117	    /** Returns a {@link Resource} for a message image. */
118	    public Resource loadMessageImage(String storedFilename) {
119	        Path file = safeResolve("messages", storedFilename);
120	        Resource resource = new FileSystemResource(file);
121	        if (!resource.exists() || !resource.isReadable()) {
122	            throw new jakarta.persistence.EntityNotFoundException("Image not found: " + storedFilename);
123	        }
124	        return resource;
125	    }
126	
127	    /** Deletes a message image silently on failure. */
128	    public void deleteMessageImage(String storedFilename) {
129	        try {
130	            Files.deleteIfExists(safeResolve("messages", storedFilename));
131	        } catch (IOException e) {
132	            log.warn("Could not delete message image {}: {}", storedFilename, e.getMessage());
133	        }
134	    }
135	
136	    // ── Private helpers ───────────────────────────────────────────────────────
137	
138	    /**
139	     * Resolves a path within {@link #rootDir} and verifies the result does not
140	     * escape the root (defense-in-depth; storedFilenames are always UUID-generated).
141	     */
142	    private Path safeResolve(String... parts) {
143	        Path resolved = rootDir;
144	        for (String part : parts) {
145	            resolved = resolved.resolve(part);
146	        }
147	        resolved = resolved.normalize();
148	        if (!resolved.startsWith(rootDir)) {
149	            throw new IllegalArgumentException("Path traversal attempt detected");
150	        }
151	        return resolved;
152	    }
153	}
