11	import org.springframework.transaction.annotation.Transactional;
12	import org.springframework.web.multipart.MultipartFile;
13	
14	import java.io.IOException;
15	import java.time.Instant;
16	import java.util.*;
17	import java.util.regex.Pattern;
18	import java.util.stream.Collectors;
19	
20	/**
21	 * Core business logic for the messaging centre.
22	 *
23	 * <h3>Read-state model</h3>
24	 * <p>When a participant opens a thread ({@link #getThread}) or polls
25	 * ({@link #pollMessages}), read receipts are inserted for every visible
26	 * message.  The composite key {@code (message_id, reader_user_id, session_id)}
27	 * gives per-device tracking: reading on one device does not mark messages
28	 * as read on another.
29	 *
30	 * <h3>Block rules</h3>
31	 * <ul>
32	 *   <li>A student may block a staff user from initiating new {@link ThreadType#DIRECT} threads.</li>
33	 *   <li>Staff can always send {@link ThreadType#SYSTEM_NOTICE} messages, bypassing all blocks.</li>
34	 *   <li>Blocks do not prevent replies within an already-open thread.</li>
35	 * </ul>
36	 */
37	@Service
38	@Transactional(readOnly = true)
39	public class MessagingService {
40	
41	    private static final Logger log = LoggerFactory.getLogger(MessagingService.class);
42	
43	    private static final Pattern JPEG_PNG = Pattern.compile("image/(jpeg|png)", Pattern.CASE_INSENSITIVE);
44	    private static final long   MAX_IMAGE_BYTES = 15L * 1024 * 1024;
45	    private static final String IMG_BASE = "/api/messages/images";
46	
47	    private final MessageThreadRepository      threadRepo;
48	    private final MessageRepository            messageRepo;
49	    private final MessageReadReceiptRepository receiptRepo;
50	    private final StaffBlockRepository         blockRepo;
51	    private final QuickReplyTemplateRepository qrRepo;
52	    private final UserRepository               userRepo;
53	    private final StorageService               storageService;
54	
55	    public MessagingService(MessageThreadRepository threadRepo,
56	                            MessageRepository messageRepo,
57	                            MessageReadReceiptRepository receiptRepo,
58	                            StaffBlockRepository blockRepo,
59	                            QuickReplyTemplateRepository qrRepo,
60	                            UserRepository userRepo,
61	                            StorageService storageService) {
62	        this.threadRepo     = threadRepo;
63	        this.messageRepo    = messageRepo;
64	        this.receiptRepo    = receiptRepo;
65	        this.blockRepo      = blockRepo;
66	        this.qrRepo         = qrRepo;
67	        this.userRepo       = userRepo;
68	        this.storageService = storageService;
69	    }
70	
71	    // ── Inbox ──────────────────────────────────────────────────────────────────
72	
73	    /**
74	     * Returns all threads the user participates in, newest-first,
75	     * with per-session unread counts.
76	     */
77	    public List<ThreadSummaryResponse> listThreads(UUID userId, String sessionId) {
78	        return threadRepo.findByParticipantUserId(userId).stream()
79	                .map(t -> toSummary(t, userId, sessionId))
80	                .collect(Collectors.toList());
81	    }
82	
83	    // ── Thread detail ──────────────────────────────────────────────────────────
84	
85	    /**
86	     * Returns full thread + messages and auto-marks every message as read
87	     * for this user+session.
88	     */
89	    @Transactional
90	    public ThreadDetailResponse getThread(UUID threadId, UUID requesterId, String sessionId) {
91	        MessageThread thread = requireThread(threadId);
92	        requireParticipant(thread, requesterId);
93	
94	        List<Message> messages = messageRepo.findByThreadIdOrderByCreatedAtAsc(threadId);
95	        batchMarkRead(messages, requesterId, sessionId);
96	
97	        Map<UUID, Long> readCounts = readCountsBySender(messages, requesterId);
98	        List<MessageResponse> msgResponses = messages.stream()
99	                .map(m -> toMessageResponse(m, requesterId, readCounts))
100	                .collect(Collectors.toList());
101	
102	        return new ThreadDetailResponse(
103	                thread.getId(), thread.getSubject(), thread.getThreadType().name(),
104	                participantInfos(thread), msgResponses, thread.getUpdatedAt()
105	        );
106	    }
107	
108	    // ── Create thread ──────────────────────────────────────────────────────────
109	
110	    /**
111	     * Creates a DIRECT thread.
112	     *
113	     * @throws BlockedException if any recipient has blocked the sender
114	     */
115	    @Transactional
116	    public ThreadSummaryResponse createThread(UUID senderId, CreateThreadRequest req) {
117	        if (blockRepo.anyRecipientBlocksStaff(req.recipientIds(), senderId)) {
118	            throw new BlockedException(
119	                    "One or more recipients have blocked you from starting new conversations.");
120	        }
121	        return buildThread(senderId, req.subject(), ThreadType.DIRECT, req.body(), req.recipientIds());
122	    }
123	
124	    // ── Send messages ──────────────────────────────────────────────────────────
125	
126	    /** Sends a text message or expands a quick-reply template. */
127	    @Transactional
128	    public MessageResponse sendMessage(UUID threadId, UUID senderId, SendMessageRequest req) {
129	        if ((req.body() == null || req.body().isBlank())
130	                && (req.quickReplyKey() == null || req.quickReplyKey().isBlank())) {
131	            throw new IllegalArgumentException("Message must have a body or a quickReplyKey.");
132	        }
133	        MessageThread thread = requireThread(threadId);
134	        requireParticipant(thread, senderId);
135	        User sender = requireUser(senderId);
136	
137	        Message msg = new Message();
138	        msg.setThread(thread);
139	        msg.setSender(sender);
140	
141	        if (req.quickReplyKey() != null && !req.quickReplyKey().isBlank()) {
142	            QuickReplyTemplate tpl = qrRepo.findByActiveTrueOrderBySortOrderAsc().stream()
143	                    .filter(t -> t.getReplyKey().equals(req.quickReplyKey()))
144	                    .findFirst()
145	                    .orElseThrow(() -> new IllegalArgumentException(
146	                            "Unknown quick-reply key: " + req.quickReplyKey()));
147	            msg.setMessageType(MessageType.QUICK_REPLY);
148	            msg.setBody(tpl.getBody());
149	            msg.setQuickReplyKey(tpl.getReplyKey());
150	        } else {
151	            msg.setMessageType(MessageType.TEXT);
152	            msg.setBody(req.body());
153	        }
154	
155	        messageRepo.save(msg);
156	        touchThread(thread);
157	        return toMessageResponse(msg, senderId, Collections.emptyMap());
158	    }
159	
160	    /** Validates, stores, and records an image message. Accepts JPEG/PNG ≤ 15 MB. */
161	    @Transactional
162	    public MessageResponse sendImageMessage(UUID threadId, UUID senderId,
163	                                            MultipartFile file) throws IOException {
164	        validateImage(file);
165	        MessageThread thread = requireThread(threadId);
166	        requireParticipant(thread, senderId);
167	        User sender = requireUser(senderId);
168	
169	        String ext = getExtension(Objects.requireNonNull(file.getOriginalFilename()));
170	        String storedFilename = UUID.randomUUID() + "." + ext;
171	        storageService.storeMessageImage(storedFilename, file);
172	
173	        Message msg = new Message();
174	        msg.setThread(thread);
175	        msg.setSender(sender);
176	        msg.setMessageType(MessageType.IMAGE);
177	        msg.setImageFilename(storedFilename);
178	        messageRepo.save(msg);
179	        touchThread(thread);
180	        return toMessageResponse(msg, senderId, Collections.emptyMap());
181	    }
182	
183	    // ── Polling ────────────────────────────────────────────────────────────────
184	
185	    /**
186	     * Returns messages created after {@code after} and marks them as read
187	     * for this user+session.  Safe to call every few seconds.
188	     */
189	    @Transactional
190	    public List<MessageResponse> pollMessages(UUID threadId, UUID userId,
191	                                              Instant after, String sessionId) {
192	        MessageThread thread = requireThread(threadId);
193	        requireParticipant(thread, userId);
194	
195	        List<Message> msgs = messageRepo.findByThreadIdAfter(threadId, after);
196	        batchMarkRead(msgs, userId, sessionId);
197	
198	        Map<UUID, Long> readCounts = readCountsBySender(msgs, userId);
199	        return msgs.stream()
200	                .map(m -> toMessageResponse(m, userId, readCounts))
201	                .collect(Collectors.toList());
202	    }
203	
204	    // ── Delete own message ─────────────────────────────────────────────────────
205	
206	    @Transactional
207	    public void deleteMessage(UUID messageId, UUID requesterId) {
208	        Message msg = messageRepo.findById(messageId)
209	                .orElseThrow(() -> new EntityNotFoundException("Message not found: " + messageId));
210	        if (msg.getSender() == null || !msg.getSender().getId().equals(requesterId)) {
211	            throw new IllegalArgumentException("You can only delete your own messages.");
212	        }
213	        msg.softDelete();
214	        messageRepo.save(msg);
215	        if (msg.getImageFilename() != null) {
216	            storageService.deleteMessageImage(msg.getImageFilename());
217	        }
218	    }
219	
220	    // ── System notices ─────────────────────────────────────────────────────────
221	
222	    /** Staff-only: creates a SYSTEM_NOTICE thread to one or more recipients, bypassing blocks. */
223	    @Transactional
224	    public void sendSystemNotice(UUID staffId, SendNoticeRequest req) {
225	        buildThread(staffId, req.subject(), ThreadType.SYSTEM_NOTICE,
226	                req.body(), req.recipientIds());
227	    }
228	
229	    // ── Quick replies ──────────────────────────────────────────────────────────
230	
231	    public List<QuickReplyResponse> listQuickReplies() {
232	        return qrRepo.findByActiveTrueOrderBySortOrderAsc().stream()
233	                .map(QuickReplyResponse::from)
234	                .collect(Collectors.toList());
235	    }
236	
237	    // ── User search ────────────────────────────────────────────────────────────
238	
239	    public List<UserSummaryResponse> searchUsers(String q, UUID currentUserId) {
240	        if (q == null || q.isBlank()) return Collections.emptyList();
241	        return userRepo.searchUsers(q.strip(), currentUserId, PageRequest.of(0, 20))
242	                .stream().map(UserSummaryResponse::from).collect(Collectors.toList());
243	    }
244	
245	    // ── Blocks ─────────────────────────────────────────────────────────────────
246	
247	    public List<BlockedStaffResponse> listBlocks(UUID studentId) {
248	        return blockRepo.findByIdStudentUserId(studentId).stream()
249	                .map(b -> {
250	                    UUID staffId = b.getId().getBlockedStaffUserId();
251	                    String name = userRepo.findById(staffId)
252	                            .map(MessagingService::displayName).orElse("Unknown");
253	                    return new BlockedStaffResponse(staffId, name, b.getCreatedAt());
254	                })
255	                .collect(Collectors.toList());
256	    }
257	
258	    @Transactional
259	    public void blockStaff(UUID studentId, UUID staffId) {
260	        if (!blockRepo.existsByIdStudentUserIdAndIdBlockedStaffUserId(studentId, staffId)) {
261	            blockRepo.save(new StaffBlock(studentId, staffId));
262	        }
263	    }
264	
265	    @Transactional
266	    public void unblockStaff(UUID studentId, UUID staffId) {
267	        StaffBlockId key = new StaffBlockId(studentId, staffId);
268	        if (blockRepo.existsById(key)) {
269	            blockRepo.deleteById(key);
270	        }
271	    }
272	
273	    // ── Private helpers ────────────────────────────────────────────────────────
274	
275	    private ThreadSummaryResponse buildThread(UUID creatorId, String subject,
276	                                              ThreadType type, String body,
277	                                              List<UUID> recipientIds) {
278	        User creator = requireUser(creatorId);
279	        MessageThread thread = new MessageThread();
280	        thread.setSubject(subject);
281	        thread.setThreadType(type);
282	        thread.setCreatedBy(creator);
283	        threadRepo.save(thread); // persist first to get the ID for the composite key
284	
285	        addParticipant(thread, creator);
286	        for (UUID rid : recipientIds) {
287	            if (!rid.equals(creatorId)) addParticipant(thread, requireUser(rid));
288	        }
289	        threadRepo.save(thread); // flush participants via cascade
290	
291	        Message msg = new Message();
292	        msg.setThread(thread);
293	        msg.setSender(creator);
294	        msg.setBody(body);
295	        msg.setMessageType(type == ThreadType.SYSTEM_NOTICE
296	                ? MessageType.SYSTEM_NOTICE : MessageType.TEXT);
297	        messageRepo.save(msg);
298	        touchThread(thread);
299	
300	        return toSummary(thread, creatorId, null);
301	    }
302	
303	    private void addParticipant(MessageThread thread, User user) {
304	        thread.getParticipants().add(new MessageThreadParticipant(thread, user));
305	    }
306	
307	    private void touchThread(MessageThread thread) {
308	        threadRepo.touchUpdatedAt(thread.getId(), Instant.now());
309	    }
310	
311	    private void batchMarkRead(List<Message> messages, UUID userId, String sessionId) {
312	        if (messages.isEmpty() || sessionId == null) return;
313	        List<UUID> ids = messages.stream().map(Message::getId).collect(Collectors.toList());
314	        Set<UUID> already = receiptRepo.findReadMessageIds(ids, userId, sessionId);
315	        List<MessageReadReceipt> toSave = new ArrayList<>();
316	        for (Message m : messages) {
317	            if (m.getSender() != null && m.getSender().getId().equals(userId)) continue;
318	            if (!already.contains(m.getId()))
319	                toSave.add(new MessageReadReceipt(m.getId(), userId, sessionId));
320	        }
321	        if (!toSave.isEmpty()) receiptRepo.saveAll(toSave);
322	    }
323	
324	    /** Returns map of messageId → count of distinct recipients who read it. */
325	    private Map<UUID, Long> readCountsBySender(List<Message> messages, UUID viewerId) {
326	        List<UUID> myIds = messages.stream()
327	                .filter(m -> m.getSender() != null && m.getSender().getId().equals(viewerId))
328	                .map(Message::getId).collect(Collectors.toList());
329	        if (myIds.isEmpty()) return Collections.emptyMap();
330	        Map<UUID, Long> counts = new HashMap<>();
331	        for (Object[] row : receiptRepo.countReadsByMessageExcludingSender(myIds, viewerId)) {
332	            counts.put((UUID) row[0], (Long) row[1]);
333	        }
334	        return counts;
335	    }
336	
337	    private MessageResponse toMessageResponse(Message m, UUID viewerId,
338	                                              Map<UUID, Long> readCounts) {
339	        String status = null;
340	        if (m.getSender() != null && m.getSender().getId().equals(viewerId)) {
341	            status = readCounts.getOrDefault(m.getId(), 0L) > 0 ? "READ" : "SENT";
342	        }
343	        return MessageResponse.from(m, IMG_BASE, status,
344	                m.getSender() != null ? displayName(m.getSender()) : "System");
345	    }
346	
347	    private ThreadSummaryResponse toSummary(MessageThread t, UUID userId, String sessionId) {
348	        Optional<Message> last = messageRepo.findLastInThread(t.getId());
349	        MessageResponse lastMsg = last.map(m -> toMessageResponse(m, userId, Collections.emptyMap()))
350	                                      .orElse(null);
351	        long unread = sessionId != null
352	                ? receiptRepo.countUnread(t.getId(), userId, sessionId)
353	                : 0L;
354	        return new ThreadSummaryResponse(t.getId(), t.getSubject(), t.getThreadType().name(),
355	                participantInfos(t), lastMsg, unread, t.getUpdatedAt());
356	    }
357	
358	    private List<ParticipantInfo> participantInfos(MessageThread t) {
359	        return t.getParticipants().stream()
360	                .map(p -> ParticipantInfo.from(p.getUser()))
361	                .collect(Collectors.toList());
362	    }
363	
364	    private MessageThread requireThread(UUID id) {
365	        return threadRepo.findById(id)
366	                .orElseThrow(() -> new EntityNotFoundException("Thread not found: " + id));
367	    }
368	
369	    private User requireUser(UUID id) {
370	        return userRepo.findById(id)
371	                .orElseThrow(() -> new EntityNotFoundException("User not found: " + id));
372	    }
373	
374	    private void requireParticipant(MessageThread thread, UUID userId) {
375	        boolean member = thread.getParticipants().stream()
376	                .anyMatch(p -> p.getId().getUserId().equals(userId));
377	        if (!member) throw new BlockedException("You are not a participant in this thread.");
378	    }
379	
380	    private static String displayName(User u) {
381	        return (u.getFirstName() != null && u.getLastName() != null)
382	                ? u.getFirstName() + " " + u.getLastName()
383	                : u.getUsername();
384	    }
385	
386	    private void validateImage(MultipartFile file) {
387	        if (file.isEmpty()) throw new IllegalArgumentException("Uploaded file is empty.");
388	        if (file.getSize() > MAX_IMAGE_BYTES)
389	            throw new IllegalArgumentException("Image exceeds the 15 MB size limit.");
390	        String ct = file.getContentType();
391	        if (ct == null || !JPEG_PNG.matcher(ct).matches())
392	            throw new IllegalArgumentException("Only JPEG and PNG images are accepted.");
393	        String name = file.getOriginalFilename();
394	        if (name == null || (!name.toLowerCase().endsWith(".jpg")
395	                && !name.toLowerCase().endsWith(".jpeg")
396	                && !name.toLowerCase().endsWith(".png")))
397	            throw new IllegalArgumentException("File extension must be .jpg, .jpeg, or .png.");
398	    }
399	
400	    private static String getExtension(String filename) {
401	        int dot = filename.lastIndexOf('.');
402	        return dot >= 0 ? filename.substring(dot + 1).toLowerCase() : "bin";
403	    }
404	}
