22	/**
23	 * Translates exceptions into consistent {@link ApiError} JSON responses.
24	 *
25	 * <p>Auth-related Spring Security exceptions ({@code AuthenticationException},
26	 * {@code AccessDeniedException}) are NOT handled here — they never reach a
27	 * {@code @ExceptionHandler} because Spring Security's filter chain intercepts
28	 * them first and the custom entry points in {@code SecurityConfig} handle them.
29	 *
30	 * <p>The only auth exception that DOES reach here is {@link BadCredentialsException}
31	 * thrown explicitly from {@code AuthService} within the controller call stack.
32	 */
33	@RestControllerAdvice
34	public class GlobalExceptionHandler {
35	
36	    private static final Logger log = LoggerFactory.getLogger(GlobalExceptionHandler.class);
37	
38	    /**
39	     * Possible duplicate residents on create — returns 409 with the candidate list
40	     * so the frontend can show a "save anyway?" confirmation.
41	     */
42	    @ExceptionHandler(DuplicateResidentException.class)
43	    public ResponseEntity<DuplicateCheckResponse> handleDuplicateResident(
44	            DuplicateResidentException ex) {
45	        return ResponseEntity.status(HttpStatus.CONFLICT).body(ex.getDuplicates());
46	    }
