1	package com.reslife.api.domain.messaging;
2	
3	import com.reslife.api.domain.user.User;
4	import com.reslife.api.domain.user.UserRepository;
5	import com.reslife.api.storage.StorageService;
6	import org.springframework.core.io.Resource;
7	import jakarta.persistence.EntityNotFoundException;
8	import org.slf4j.Logger;
9	import org.slf4j.LoggerFactory;
10	import org.springframework.data.domain.PageRequest;
11	import org.springframework.stereotype.Service;
12	import org.springframework.transaction.annotation.Transactional;
13	import org.springframework.web.multipart.MultipartFile;
14	
15	import java.io.IOException;
16	import java.time.Instant;
17	import java.util.*;
18	import java.util.regex.Pattern;
19	import java.util.stream.Collectors;
20	
21	/**
22	 * Core business logic for the messaging centre.
23	 *
24	 * <h3>Read-state model</h3>
25	 * <p>When a participant opens a thread ({@link #getThread}) or polls
26	 * ({@link #pollMessages}), read receipts are inserted for every visible
27	 * message.  The composite key {@code (message_id, reader_user_id, session_id)}
28	 * gives per-device tracking: reading on one device does not mark messages
29	 * as read on another.
30	 *
31	 * <h3>Block rules</h3>
32	 * <ul>
33	 *   <li>A student may block a staff user from initiating new {@link ThreadType#DIRECT} threads.</li>
34	 *   <li>Staff can always send {@link ThreadType#SYSTEM_NOTICE} messages, bypassing all blocks.</li>
35	 *   <li>Blocks do not prevent replies within an already-open thread.</li>
36	 * </ul>
37	 */
38	@Service
39	@Transactional(readOnly = true)
40	public class MessagingService {
41	
42	    private static final Logger log = LoggerFactory.getLogger(MessagingService.class);
43	
44	    private static final Pattern JPEG_PNG = Pattern.compile("image/(jpeg|png)", Pattern.CASE_INSENSITIVE);
45	    private static final long   MAX_IMAGE_BYTES = 15L * 1024 * 1024;
46	    private static final String IMG_BASE = "/api/messages/images";
47	
48	    private final MessageThreadRepository      threadRepo;
49	    private final MessageRepository            messageRepo;
50	    private final MessageReadReceiptRepository receiptRepo;
51	    private final StaffBlockRepository         blockRepo;
52	    private final QuickReplyTemplateRepository qrRepo;
53	    private final UserRepository               userRepo;
54	    private final StorageService               storageService;
55	
56	    public MessagingService(MessageThreadRepository threadRepo,
57	                            MessageRepository messageRepo,
58	                            MessageReadReceiptRepository receiptRepo,
59	                            StaffBlockRepository blockRepo,
60	                            QuickReplyTemplateRepository qrRepo,
61	                            UserRepository userRepo,
62	                            StorageService storageService) {
63	        this.threadRepo     = threadRepo;
64	        this.messageRepo    = messageRepo;
65	        this.receiptRepo    = receiptRepo;
66	        this.blockRepo      = blockRepo;
67	        this.qrRepo         = qrRepo;
68	        this.userRepo       = userRepo;
69	        this.storageService = storageService;
70	    }
71	
72	    // ── Inbox ──────────────────────────────────────────────────────────────────
73	
74	    /**
75	     * Returns all threads the user participates in, newest-first,
76	     * with per-session unread counts.
77	     */
78	    public List<ThreadSummaryResponse> listThreads(UUID userId, String sessionId) {
79	        return threadRepo.findByParticipantUserId(userId).stream()
80	                .map(t -> toSummary(t, userId, sessionId))
81	                .collect(Collectors.toList());
82	    }
83	
84	    // ── Thread detail ──────────────────────────────────────────────────────────
85	
86	    /**
87	     * Returns full thread + messages and auto-marks every message as read
88	     * for this user+session.
89	     */
90	    @Transactional
91	    public ThreadDetailResponse getThread(UUID threadId, UUID requesterId, String sessionId) {
92	        MessageThread thread = requireThread(threadId);
93	        requireParticipant(thread, requesterId);
94	
95	        List<Message> messages = messageRepo.findByThreadIdOrderByCreatedAtAsc(threadId);
96	        batchMarkRead(messages, requesterId, sessionId);
97	
98	        Map<UUID, Long> readCounts = readCountsBySender(messages, requesterId);
99	        List<MessageResponse> msgResponses = messages.stream()
100	                .map(m -> toMessageResponse(m, requesterId, readCounts))
101	                .collect(Collectors.toList());
102	
103	        return new ThreadDetailResponse(
104	                thread.getId(), thread.getSubject(), thread.getThreadType().name(),
105	                participantInfos(thread), msgResponses, thread.getUpdatedAt()
106	        );
107	    }
108	
109	    // ── Create thread ──────────────────────────────────────────────────────────
110	
111	    /**
112	     * Creates a DIRECT thread.
113	     *
114	     * @throws BlockedException if any recipient has blocked the sender
115	     */
116	    @Transactional
117	    public ThreadSummaryResponse createThread(UUID senderId, CreateThreadRequest req) {
118	        if (blockRepo.anyRecipientBlocksStaff(req.recipientIds(), senderId)) {
119	            throw new BlockedException(
120	                    "One or more recipients have blocked you from starting new conversations.");
121	        }
122	        return buildThread(senderId, req.subject(), ThreadType.DIRECT, req.body(), req.recipientIds());
123	    }
124	
125	    // ── Send messages ──────────────────────────────────────────────────────────
126	
127	    /** Sends a text message or expands a quick-reply template. */
128	    @Transactional
129	    public MessageResponse sendMessage(UUID threadId, UUID senderId, SendMessageRequest req) {
130	        if ((req.body() == null || req.body().isBlank())
131	                && (req.quickReplyKey() == null || req.quickReplyKey().isBlank())) {
132	            throw new IllegalArgumentException("Message must have a body or a quickReplyKey.");
133	        }
134	        MessageThread thread = requireThread(threadId);
135	        requireParticipant(thread, senderId);
136	        User sender = requireUser(senderId);
137	
138	        Message msg = new Message();
139	        msg.setThread(thread);
140	        msg.setSender(sender);
141	
142	        if (req.quickReplyKey() != null && !req.quickReplyKey().isBlank()) {
143	            QuickReplyTemplate tpl = qrRepo.findByActiveTrueOrderBySortOrderAsc().stream()
144	                    .filter(t -> t.getReplyKey().equals(req.quickReplyKey()))
145	                    .findFirst()
146	                    .orElseThrow(() -> new IllegalArgumentException(
147	                            "Unknown quick-reply key: " + req.quickReplyKey()));
148	            msg.setMessageType(MessageType.QUICK_REPLY);
149	            msg.setBody(tpl.getBody());
150	            msg.setQuickReplyKey(tpl.getReplyKey());
151	        } else {
152	            msg.setMessageType(MessageType.TEXT);
153	            msg.setBody(req.body());
154	        }
155	
156	        messageRepo.save(msg);
157	        touchThread(thread);
158	        return toMessageResponse(msg, senderId, Collections.emptyMap());
159	    }
160	
161	    /** Validates, stores, and records an image message. Accepts JPEG/PNG ≤ 15 MB. */
162	    @Transactional
163	    public MessageResponse sendImageMessage(UUID threadId, UUID senderId,
164	                                            MultipartFile file) throws IOException {
165	        validateImage(file);
166	        MessageThread thread = requireThread(threadId);
167	        requireParticipant(thread, senderId);
168	        User sender = requireUser(senderId);
169	
170	        String ext = getExtension(Objects.requireNonNull(file.getOriginalFilename()));
171	        String storedFilename = UUID.randomUUID() + "." + ext;
172	        storageService.storeMessageImage(storedFilename, file);
173	
174	        Message msg = new Message();
175	        msg.setThread(thread);
176	        msg.setSender(sender);
177	        msg.setMessageType(MessageType.IMAGE);
178	        msg.setImageFilename(storedFilename);
179	        messageRepo.save(msg);
180	        touchThread(thread);
181	        return toMessageResponse(msg, senderId, Collections.emptyMap());
182	    }
183	
184	    // ── Polling ────────────────────────────────────────────────────────────────
185	
186	    /**
187	     * Returns messages created after {@code after} and marks them as read
188	     * for this user+session.  Safe to call every few seconds.
189	     */
190	    @Transactional
191	    public List<MessageResponse> pollMessages(UUID threadId, UUID userId,
192	                                              Instant after, String sessionId) {
193	        MessageThread thread = requireThread(threadId);
194	        requireParticipant(thread, userId);
195	
196	        List<Message> msgs = messageRepo.findByThreadIdAfter(threadId, after);
197	        batchMarkRead(msgs, userId, sessionId);
198	
199	        Map<UUID, Long> readCounts = readCountsBySender(msgs, userId);
200	        return msgs.stream()
201	                .map(m -> toMessageResponse(m, userId, readCounts))
202	                .collect(Collectors.toList());
203	    }
204	
205	    // ── Delete own message ─────────────────────────────────────────────────────
206	
207	    @Transactional
208	    public void deleteMessage(UUID messageId, UUID requesterId) {
209	        Message msg = messageRepo.findById(messageId)
210	                .orElseThrow(() -> new EntityNotFoundException("Message not found: " + messageId));
211	        if (msg.getSender() == null || !msg.getSender().getId().equals(requesterId)) {
212	            throw new IllegalArgumentException("You can only delete your own messages.");
213	        }
214	        msg.softDelete();
215	        messageRepo.save(msg);
216	        if (msg.getImageFilename() != null) {
217	            storageService.deleteMessageImage(msg.getImageFilename());
218	        }
219	    }
220	
221	    // ── System notices ─────────────────────────────────────────────────────────
222	
223	    /** Staff-only: creates a SYSTEM_NOTICE thread to one or more recipients, bypassing blocks. */
224	    @Transactional
225	    public void sendSystemNotice(UUID staffId, SendNoticeRequest req) {
226	        buildThread(staffId, req.subject(), ThreadType.SYSTEM_NOTICE,
227	                req.body(), req.recipientIds());
228	    }
229	
230	    // ── Image serving ─────────────────────────────────────────────────────────
231	
232	    /**
233	     * Loads a message image, gated on thread-participant membership.
234	     *
235	     * @throws EntityNotFoundException if no message owns {@code filename}
236	     * @throws BlockedException        if the requester is not a thread participant (→ 403)
237	     */
238	    public Resource serveImageAsParticipant(String filename, UUID requesterId) {
239	        Message msg = messageRepo.findByImageFilename(filename)
240	                .orElseThrow(() -> new EntityNotFoundException("Image not found: " + filename));
241	        requireParticipant(msg.getThread(), requesterId);
242	        return storageService.loadMessageImage(filename);
243	    }
244	
245	    // ── Quick replies ──────────────────────────────────────────────────────────
246	
247	    public List<QuickReplyResponse> listQuickReplies() {
248	        return qrRepo.findByActiveTrueOrderBySortOrderAsc().stream()
249	                .map(QuickReplyResponse::from)
250	                .collect(Collectors.toList());
251	    }
252	
253	    // ── User search ────────────────────────────────────────────────────────────
254	
255	    public List<UserSummaryResponse> searchUsers(String q, UUID currentUserId) {
256	        if (q == null || q.isBlank()) return Collections.emptyList();
257	        return userRepo.searchUsers(q.strip(), currentUserId, PageRequest.of(0, 20))
258	                .stream().map(UserSummaryResponse::from).collect(Collectors.toList());
259	    }
260	
261	    // ── Blocks ─────────────────────────────────────────────────────────────────
262	
263	    public List<BlockedStaffResponse> listBlocks(UUID studentId) {
264	        return blockRepo.findByIdStudentUserId(studentId).stream()
265	                .map(b -> {
266	                    UUID staffId = b.getId().getBlockedStaffUserId();
267	                    String name = userRepo.findById(staffId)
268	                            .map(MessagingService::displayName).orElse("Unknown");
269	                    return new BlockedStaffResponse(staffId, name, b.getCreatedAt());
270	                })
271	                .collect(Collectors.toList());
272	    }
273	
274	    @Transactional
275	    public void blockStaff(UUID studentId, UUID staffId) {
276	        if (!blockRepo.existsByIdStudentUserIdAndIdBlockedStaffUserId(studentId, staffId)) {
277	            blockRepo.save(new StaffBlock(studentId, staffId));
278	        }
279	    }
280	
281	    @Transactional
282	    public void unblockStaff(UUID studentId, UUID staffId) {
283	        StaffBlockId key = new StaffBlockId(studentId, staffId);
284	        if (blockRepo.existsById(key)) {
285	            blockRepo.deleteById(key);
286	        }
287	    }
288	
289	    // ── Private helpers ────────────────────────────────────────────────────────
290	
291	    private ThreadSummaryResponse buildThread(UUID creatorId, String subject,
292	                                              ThreadType type, String body,
293	                                              List<UUID> recipientIds) {
294	        User creator = requireUser(creatorId);
295	        MessageThread thread = new MessageThread();
296	        thread.setSubject(subject);
297	        thread.setThreadType(type);
298	        thread.setCreatedBy(creator);
299	        threadRepo.save(thread); // persist first to get the ID for the composite key
300	
301	        addParticipant(thread, creator);
302	        for (UUID rid : recipientIds) {
303	            if (!rid.equals(creatorId)) addParticipant(thread, requireUser(rid));
304	        }
305	        threadRepo.save(thread); // flush participants via cascade
306	
307	        Message msg = new Message();
308	        msg.setThread(thread);
309	        msg.setSender(creator);
310	        msg.setBody(body);
311	        msg.setMessageType(type == ThreadType.SYSTEM_NOTICE
312	                ? MessageType.SYSTEM_NOTICE : MessageType.TEXT);
313	        messageRepo.save(msg);
314	        touchThread(thread);
315	
316	        return toSummary(thread, creatorId, null);
317	    }
318	
319	    private void addParticipant(MessageThread thread, User user) {
320	        thread.getParticipants().add(new MessageThreadParticipant(thread, user));
321	    }
322	
323	    private void touchThread(MessageThread thread) {
324	        threadRepo.touchUpdatedAt(thread.getId(), Instant.now());
325	    }
326	
327	    private void batchMarkRead(List<Message> messages, UUID userId, String sessionId) {
328	        if (messages.isEmpty() || sessionId == null) return;
329	        List<UUID> ids = messages.stream().map(Message::getId).collect(Collectors.toList());
330	        Set<UUID> already = receiptRepo.findReadMessageIds(ids, userId, sessionId);
331	        List<MessageReadReceipt> toSave = new ArrayList<>();
332	        for (Message m : messages) {
333	            if (m.getSender() != null && m.getSender().getId().equals(userId)) continue;
334	            if (!already.contains(m.getId()))
335	                toSave.add(new MessageReadReceipt(m.getId(), userId, sessionId));
336	        }
337	        if (!toSave.isEmpty()) receiptRepo.saveAll(toSave);
338	    }
339	
340	    /** Returns map of messageId → count of distinct recipients who read it. */
341	    private Map<UUID, Long> readCountsBySender(List<Message> messages, UUID viewerId) {
342	        List<UUID> myIds = messages.stream()
343	                .filter(m -> m.getSender() != null && m.getSender().getId().equals(viewerId))
344	                .map(Message::getId).collect(Collectors.toList());
345	        if (myIds.isEmpty()) return Collections.emptyMap();
346	        Map<UUID, Long> counts = new HashMap<>();
347	        for (Object[] row : receiptRepo.countReadsByMessageExcludingSender(myIds, viewerId)) {
348	            counts.put((UUID) row[0], (Long) row[1]);
349	        }
350	        return counts;
351	    }
352	
353	    private MessageResponse toMessageResponse(Message m, UUID viewerId,
354	                                              Map<UUID, Long> readCounts) {
355	        String status = null;
356	        if (m.getSender() != null && m.getSender().getId().equals(viewerId)) {
357	            status = readCounts.getOrDefault(m.getId(), 0L) > 0 ? "READ" : "SENT";
358	        }
359	        return MessageResponse.from(m, IMG_BASE, status,
360	                m.getSender() != null ? displayName(m.getSender()) : "System");
361	    }
362	
363	    private ThreadSummaryResponse toSummary(MessageThread t, UUID userId, String sessionId) {
364	        Optional<Message> last = messageRepo.findLastInThread(t.getId());
365	        MessageResponse lastMsg = last.map(m -> toMessageResponse(m, userId, Collections.emptyMap()))
366	                                      .orElse(null);
367	        long unread = sessionId != null
368	                ? receiptRepo.countUnread(t.getId(), userId, sessionId)
369	                : 0L;
370	        return new ThreadSummaryResponse(t.getId(), t.getSubject(), t.getThreadType().name(),
371	                participantInfos(t), lastMsg, unread, t.getUpdatedAt());
372	    }
373	
374	    private List<ParticipantInfo> participantInfos(MessageThread t) {
375	        return t.getParticipants().stream()
376	                .map(p -> ParticipantInfo.from(p.getUser()))
377	                .collect(Collectors.toList());
378	    }
379	
380	    private MessageThread requireThread(UUID id) {
381	        return threadRepo.findById(id)
382	                .orElseThrow(() -> new EntityNotFoundException("Thread not found: " + id));
383	    }
384	
385	    private User requireUser(UUID id) {
386	        return userRepo.findById(id)
387	                .orElseThrow(() -> new EntityNotFoundException("User not found: " + id));
388	    }
389	
390	    private void requireParticipant(MessageThread thread, UUID userId) {
391	        boolean member = thread.getParticipants().stream()
392	                .anyMatch(p -> p.getId().getUserId().equals(userId));
393	        if (!member) throw new BlockedException("You are not a participant in this thread.");
394	    }
395	
396	    private static String displayName(User u) {
397	        return (u.getFirstName() != null && u.getLastName() != null)
398	                ? u.getFirstName() + " " + u.getLastName()
399	                : u.getUsername();
400	    }
401	
402	    private void validateImage(MultipartFile file) {
403	        if (file.isEmpty()) throw new IllegalArgumentException("Uploaded file is empty.");
404	        if (file.getSize() > MAX_IMAGE_BYTES)
405	            throw new IllegalArgumentException("Image exceeds the 15 MB size limit.");
406	        String ct = file.getContentType();
407	        if (ct == null || !JPEG_PNG.matcher(ct).matches())
408	            throw new IllegalArgumentException("Only JPEG and PNG images are accepted.");
409	        String name = file.getOriginalFilename();
410	        if (name == null || (!name.toLowerCase().endsWith(".jpg")
411	                && !name.toLowerCase().endsWith(".jpeg")
412	                && !name.toLowerCase().endsWith(".png")))
413	            throw new IllegalArgumentException("File extension must be .jpg, .jpeg, or .png.");
414	    }
415	
416	    private static String getExtension(String filename) {
417	        int dot = filename.lastIndexOf('.');
418	        return dot >= 0 ? filename.substring(dot + 1).toLowerCase() : "bin";
419	    }
420	}
