20	public class MessageThread extends SoftDeletableEntity {
21	
22	    @Column(length = 255)
23	    private String subject;
24	
25	    @Enumerated(EnumType.STRING)
26	    @Column(name = "thread_type", nullable = false, length = 50)
27	    private ThreadType threadType = ThreadType.DIRECT;
