1	/**
2	 * Thin fetch wrapper that:
3	 *  - Always sends credentials (session cookie)
4	 *  - Reads the XSRF-TOKEN cookie and attaches it as X-XSRF-TOKEN on
5	 *    mutating requests (POST, PUT, PATCH, DELETE)
6	 *  - On error, throws an HttpError with `status` and `body` fields so
7	 *    callers can handle specific status codes (e.g. 409 duplicate check)
8	 */
9	
10	const CSRF_COOKIE  = 'XSRF-TOKEN';
11	const CSRF_HEADER  = 'X-XSRF-TOKEN';
12	const MUTATING     = new Set(['POST', 'PUT', 'PATCH', 'DELETE']);
13	
14	/** Error thrown for non-2xx responses. Carries the HTTP status and parsed body. */
15	export class HttpError extends Error {
16	  constructor(status, body) {
17	    super(body?.message || body?.error || `HTTP ${status}`);
18	    this.status = status;
19	    this.body   = body;
20	  }
21	}
22	
23	function getCsrfToken() {
24	  const match = document.cookie
25	    .split('; ')
26	    .find(row => row.startsWith(CSRF_COOKIE + '='));
27	  return match ? decodeURIComponent(match.split('=')[1]) : '';
28	}
29	
30	async function request(method, path, body) {
31	  const headers = { 'Content-Type': 'application/json' };
32	  if (MUTATING.has(method)) {
33	    headers[CSRF_HEADER] = getCsrfToken();
34	  }
35	
36	  const res = await fetch(path, {
37	    method,
38	    credentials: 'include',
39	    headers,
40	    body: body !== undefined ? JSON.stringify(body) : undefined,
41	  });
42	
43	  if (res.status === 204) return null;
44	
45	  const data = await res.json().catch(() => ({}));
46	  if (!res.ok) {
47	    throw new HttpError(res.status, data);
48	  }
49	  return data;
50	}
51	
52	/**
53	 * Multipart file upload helper.
54	 * Does NOT set Content-Type — the browser sets it automatically with the
55	 * correct boundary when the body is a FormData instance.
56	 */
57	async function uploadFile(path, formData) {
58	  const res = await fetch(path, {
59	    method: 'POST',
60	    credentials: 'include',
61	    headers: { [CSRF_HEADER]: getCsrfToken() },
62	    body: formData,
63	  });
64	
65	  if (res.status === 204) return null;
66	  const data = await res.json().catch(() => ({}));
67	  if (!res.ok) throw new HttpError(res.status, data);
68	  return data;
69	}
70	
71	export const api = {
72	  get:    (path)              => request('GET',    path),
73	  post:   (path, body)        => request('POST',   path, body),
74	  put:    (path, body)        => request('PUT',    path, body),
75	  patch:  (path, body)        => request('PATCH',  path, body),
76	  delete: (path)              => request('DELETE', path),
77	  upload: (path, formData)    => uploadFile(path, formData),
78	};
