243	  }, [threadId]);
244	
245	  useEffect(() => { setTimeout(scrollBottom, 100); }, [messages.length]);
246	
247	  const pickImage = (e) => {
248	    const file = e.target.files[0];
249	    if (!file) return;
250	    if (file.size > MAX_IMG_BYTES) { setError('Image must be under 15 MB.'); return; }
251	    setImgFile(file);
252	    setImgPreview(URL.createObjectURL(file));
253	    setError('');
