259	    setImgPreview(null);
260	  };
261	
262	  const send = async () => {
263	    if (sending) return;
264	    if (!body.trim() && !imgFile) return;
265	    setSending(true); setError('');
266	    try {
267	      let newMsg;
268	      if (imgFile) {
269	        const form = new FormData();
270	        form.append('file', imgFile);
271	        newMsg = await api.upload(`/api/messages/threads/${threadId}/messages/image`, form);
272	        clearImage();
273	      } else {
274	        newMsg = await api.post(`/api/messages/threads/${threadId}/messages`, { body: body.trim() });
275	      }
276	      setBody('');
277	      setMessages(prev => {
278	        if (prev.find(m => m.id === newMsg.id)) return prev;
279	        return [...prev, newMsg];
280	      });
281	      lastMsgTimeRef.current = newMsg.createdAt;
282	      setTimeout(scrollBottom, 50);
283	    } catch (e) {
284	      setError(e.body?.message || e.message || 'Failed to send.');
285	    } finally { setSending(false); }
286	  };
287	
288	  const sendQuickReply = async (r) => {
289	    setSending(true); setError('');
