Runs every **3 seconds** (THREAD_POLL_MS = 3000):
```javascript
useEffect(() => {
    const id = setInterval(async () => {
      if (!lastMsgTimeRef.current) return;
      try {
        const newMsgs = await api.get(
          `/api/messages/threads/${threadId}/poll?after=${encodeURIComponent(lastMsgTimeRef.current)}`
        );
        if (newMsgs.length) {
          setMessages(prev => {
            const existingIds = new Set(prev.map(m => m.id));
            const added = newMsgs.filter(m => !existingIds.has(m.id));
            return [...prev, ...added];
          });
          lastMsgTimeRef.current = newMsgs[newMsgs.length - 1].createdAt;
          setTimeout(scrollBottom, 50);
        }
      } catch (_) {}
    }, THREAD_POLL_MS);
    return () => clearInterval(id);
  }, [threadId]);
```

