2	
3	import jakarta.servlet.http.HttpServletRequest;
4	import org.springframework.web.bind.annotation.*;
5	
6	import java.time.Instant;
7	
8	/**
9	 * Receives inbound events from authenticated local on-prem systems.
10	 *
11	 * <p>By the time a request reaches this controller, {@link IntegrationAuthFilter}
12	 * has already verified the HMAC signature, confirmed the timestamp is within the
13	 * 5-minute replay window, and checked the rate limit.  The resolved
14	 * {@link IntegrationKey} is available as a request attribute.
15	 *
16	 * <pre>
17	 * POST /api/integrations/events/{eventType}
18	 * </pre>
19	 */
20	@RestController
21	@RequestMapping("/api/integrations")
22	public class InboundController {
23	
24	    private final IntegrationAuditLogRepository auditRepo;
25	
26	    public InboundController(IntegrationAuditLogRepository auditRepo) {
27	        this.auditRepo = auditRepo;
28	    }
29	
30	    /**
31	     * Accepts an inbound event from a local system and records it in the audit log.
32	     *
33	     * @param eventType dot-separated event identifier, e.g. {@code "device.checkin"}
34	     * @param body      raw JSON payload (optional — some events carry no body)
35	     */
36	    @PostMapping("/events/{eventType}")
37	    public InboundEventResponse receive(
38	            @PathVariable String eventType,
39	            @RequestBody(required = false) String body,
40	            HttpServletRequest request) {
41	
42	        IntegrationKey key       = (IntegrationKey) request.getAttribute(IntegrationAuthFilter.KEY_ATTR);
43	        String         requestId = request.getHeader("X-Request-ID");
44	        String         sourceIp  = request.getRemoteAddr();
45	
46	        IntegrationAuditLog entry = new IntegrationAuditLog();
47	        entry.setIntegrationKey(key);
48	        entry.setDirection(IntegrationAuditLog.Direction.INBOUND);
49	        entry.setEventType(eventType);
50	        entry.setSourceIp(sourceIp);
51	        entry.setHttpStatus(200);
52	        entry.setSuccess(true);
53	        entry.setRequestId(requestId);
54	        auditRepo.save(entry);
55	
56	        return new InboundEventResponse("accepted", eventType, requestId, Instant.now());
57	    }
58	}
