73	            FilterChain chain = inv.getArgument(2);
74	            chain.doFilter(inv.getArgument(0), inv.getArgument(1));
75	            return null;
76	        }).when(integrationAuthFilter).doFilter(any(), any(), any());
77	
78	        // AccountStatusFilter (real @Component bean) performs a findById check for every
79	        // ReslifeUserDetails principal.  Return an ACTIVE user for any UUID so the filter
80	        // passes through without invalidating the session.
81	        User active = new User(); // accountStatus defaults to ACTIVE via field initialiser
