1	package com.reslife.api.admin;
2	
3	import com.reslife.api.domain.system.AuditLog;
4	import com.reslife.api.domain.system.AuditLogRepository;
5	import com.reslife.api.domain.user.AccountStatus;
6	import com.reslife.api.domain.user.FailedLoginAttemptRepository;
7	import com.reslife.api.domain.user.User;
8	import com.reslife.api.domain.user.UserRepository;
9	import jakarta.persistence.EntityNotFoundException;
10	import jakarta.servlet.http.HttpServletRequest;
11	import org.springframework.scheduling.annotation.Scheduled;
12	import org.springframework.session.FindByIndexNameSessionRepository;
13	import org.springframework.session.Session;
14	import org.springframework.stereotype.Service;
15	import org.springframework.transaction.annotation.Transactional;
16	
17	import java.time.Instant;
18	import java.time.temporal.ChronoUnit;
19	import java.util.Map;
20	import java.util.UUID;
21	
22	@Service
23	@Transactional(readOnly = true)
24	public class AdminUserService {
25	
26	    private final UserRepository userRepository;
27	    private final AuditLogRepository auditLogRepository;
28	    private final FailedLoginAttemptRepository attemptRepository;
29	    private final FindByIndexNameSessionRepository<? extends Session> sessionRepository;
30	
31	    public AdminUserService(UserRepository userRepository,
32	                            AuditLogRepository auditLogRepository,
33	                            FailedLoginAttemptRepository attemptRepository,
34	                            FindByIndexNameSessionRepository<? extends Session> sessionRepository) {
35	        this.userRepository = userRepository;
36	        this.auditLogRepository = auditLogRepository;
37	        this.attemptRepository = attemptRepository;
38	        this.sessionRepository = sessionRepository;
39	    }
40	
41	    // -----------------------------------------------------------------------
42	    // Account status management
43	    // -----------------------------------------------------------------------
44	
45	    /**
46	     * Changes a user's account status.
47	     *
48	     * <p>Rules:
49	     * <ul>
50	     *   <li>An admin cannot change their own account status.</li>
51	     *   <li>Disabling starts the 30-day purge clock.</li>
52	     *   <li>Re-activating cancels the purge clock.</li>
53	     *   <li>Any status change immediately kills all active sessions for the target user.</li>
54	     * </ul>
55	     */
56	    @Transactional
57	    public User updateAccountStatus(UUID targetUserId, AccountStatus newStatus, String reason,
58	                                    UUID actorUserId, HttpServletRequest httpRequest) {
59	        if (targetUserId.equals(actorUserId)) {
60	            throw new IllegalArgumentException("Administrators cannot change their own account status.");
61	        }
62	
63	        User target = userRepository.findById(targetUserId)
64	                .orElseThrow(() -> new EntityNotFoundException("User not found: " + targetUserId));
65	
66	        AccountStatus oldStatus = target.getAccountStatus();
67	
68	        target.setAccountStatus(newStatus);
69	        target.setStatusReason(reason);
70	        target.setStatusChangedBy(actorUserId);
71	        target.setStatusChangedAt(Instant.now());
72	
73	        switch (newStatus) {
74	            case DISABLED -> {
75	                // Start the 30-day purge clock only on first disable
76	                if (target.getScheduledPurgeAt() == null) {
77	                    target.setScheduledPurgeAt(Instant.now().plus(30, ChronoUnit.DAYS));
78	                }
79	            }
80	            case ACTIVE -> {
81	                // Re-activation cancels any scheduled purge
82	                target.setScheduledPurgeAt(null);
83	            }
84	            default -> { /* FROZEN and BLACKLISTED: no purge clock change */ }
85	        }
86	
87	        userRepository.save(target);
88	
89	        // Immediately expire all active sessions for the affected user
90	        invalidateUserSessions(target.getUsername());
91	
92	        // Audit the action
93	        String ip = extractClientIp(httpRequest);
94	        String ua = httpRequest.getHeader("User-Agent");
95	        auditStatusChange(target, oldStatus, newStatus, reason, actorUserId, ip, ua);
96	
97	        return target;
98	    }
99	
100	    // -----------------------------------------------------------------------
101	    // Account deletion
102	    // -----------------------------------------------------------------------
103	
104	    /**
105	     * Soft-deletes a user account and schedules it for permanent purge in 30 days.
106	     *
107	     * <p>Unlike {@link #updateAccountStatus}, this is a one-way operation:
108	     * the account is immediately soft-deleted ({@code deleted_at} set) so the
109	     * nightly purge job can find and permanently remove it when the grace period
110	     * expires. All active sessions are invalidated and the action is audit-logged.
111	     */
112	    @Transactional
113	    public void deleteAccount(UUID targetUserId, UUID actorUserId, HttpServletRequest httpRequest) {
114	        if (targetUserId.equals(actorUserId)) {
115	            throw new IllegalArgumentException("Administrators cannot delete their own account.");
116	        }
117	
118	        User target = userRepository.findById(targetUserId)
119	                .orElseThrow(() -> new EntityNotFoundException("User not found: " + targetUserId));
120	
121	        target.softDelete();
122	        target.setScheduledPurgeAt(Instant.now().plus(30, ChronoUnit.DAYS));
123	        target.setAccountStatus(AccountStatus.DISABLED);
124	        target.setStatusChangedBy(actorUserId);
125	        target.setStatusChangedAt(Instant.now());
126	
127	        userRepository.save(target);
128	
129	        invalidateUserSessions(target.getUsername());
130	
131	        User actor = userRepository.findById(actorUserId).orElse(null);
132	        String ip = extractClientIp(httpRequest);
133	        String ua = httpRequest.getHeader("User-Agent");
134	
135	        AuditLog entry = new AuditLog();
136	        entry.setUser(actor);
137	        snapshotActor(entry, actor);
138	        entry.setAction("ACCOUNT_DELETED");
139	        entry.setEntityType("User");
140	        entry.setEntityId(target.getId());
141	        entry.setNewValues("{\"scheduledPurgeAt\":\"" + target.getScheduledPurgeAt() + "\"}");
142	        entry.setIpAddress(ip);
143	        entry.setUserAgent(ua);
144	        auditLogRepository.save(entry);
145	    }
146	
147	    // -----------------------------------------------------------------------
148	    // Scheduled maintenance
149	    // -----------------------------------------------------------------------
150	
151	    /**
152	     * Hard-deletes accounts whose 30-day grace period has expired.
153	     * Runs daily at 02:00. A deletion is logged as an audit entry before
154	     * the row is removed.
155	     */
156	    @Scheduled(cron = "0 0 2 * * *")
157	    @Transactional
158	    public void purgeExpiredAccounts() {
159	        Instant now = Instant.now();
160	        int purged = userRepository.hardDeletePurgeableUsers(now);
161	        if (purged > 0) {
162	            AuditLog entry = new AuditLog();
163	            entry.setAction("PURGE_SCHEDULED");
164	            entry.setEntityType("User");
165	            entry.setNewValues("{\"purgedCount\":" + purged + "}");
166	            auditLogRepository.save(entry);
167	        }
168	    }
169	
170	    /**
171	     * Removes login attempt records older than 30 days to control table growth.
172	     * Runs daily at 03:00.
173	     */
174	    @Scheduled(cron = "0 0 3 * * *")
175	    @Transactional
176	    public void cleanupLoginAttempts() {
177	        Instant cutoff = Instant.now().minus(30, ChronoUnit.DAYS);
178	        attemptRepository.deleteOlderThan(cutoff);
179	    }
180	
181	    // -----------------------------------------------------------------------
182	    // Helpers
183	    // -----------------------------------------------------------------------
184	
185	    private void invalidateUserSessions(String username) {
186	        try {
187	            Map<String, ? extends Session> sessions =
188	                    sessionRepository.findByPrincipalName(username);
189	            sessions.forEach((id, session) -> sessionRepository.deleteById(id));
190	        } catch (Exception ignored) {
191	            // Session store may be unavailable during tests; swallow silently
192	        }
193	    }
194	
195	    private void auditStatusChange(User target, AccountStatus oldStatus, AccountStatus newStatus,
196	                                   String reason, UUID actorUserId, String ip, String ua) {
197	        User actor = userRepository.findById(actorUserId).orElse(null);
198	
199	        AuditLog entry = new AuditLog();
200	        entry.setUser(actor);
201	        snapshotActor(entry, actor);
202	        entry.setAction("ACCOUNT_STATUS_CHANGE");
203	        entry.setEntityType("User");
204	        entry.setEntityId(target.getId());
205	        entry.setOldValues("{\"accountStatus\":\"" + oldStatus + "\"}");
206	        entry.setNewValues("{\"accountStatus\":\"" + newStatus + "\",\"reason\":\""
207	                + (reason != null ? reason.replace("\"", "\\\"") : "") + "\"}");
208	        entry.setIpAddress(ip);
209	        entry.setUserAgent(ua);
210	        auditLogRepository.save(entry);
211	    }
212	
213	    /**
214	     * Copies the actor's username and email into the audit entry at write time.
215	     * These snapshot columns survive even after the actor's user row is hard-purged
216	     * (the {@code user_id} FK becomes NULL; the text values remain).
217	     */
218	    private void snapshotActor(AuditLog entry, User actor) {
219	        if (actor != null) {
220	            entry.setActorUsername(actor.getUsername());
221	            entry.setActorEmail(actor.getEmail());
222	        }
223	    }
224	
225	    private String extractClientIp(HttpServletRequest request) {
226	        String forwarded = request.getHeader("X-Forwarded-For");
227	        if (forwarded != null && !forwarded.isBlank()) {
228	            return forwarded.split(",")[0].strip();
229	        }
230	        return request.getRemoteAddr();
231	    }
232	}
